    pub fn search_text(
        &self,
        query: &str,
        from_sec: u32,
        from_para: u32,
        from_char: u32,
        forward: bool,
        case_sensitive: bool,
    ) -> Result<String> {
        self.ensure_section(from_sec)?;
        if query.is_empty() {
            return Ok("{\"found\":false}".to_string());
        }

        let hits = self.search_hits(query, case_sensitive);
        if hits.is_empty() {
            return Ok("{\"found\":false}".to_string());
        }

        if forward {
            let after = hits.iter().find(|hit| {
                hit.sec > from_sec
                    || (hit.sec == from_sec && hit.para > from_para)
                    || (hit.sec == from_sec && hit.para == from_para && hit.char_offset > from_char)
            });
            Ok(match after {
                Some(hit) => format_search_result(hit, false),
                None => format_search_result(&hits[0], true),
            })
        } else {
            let before = hits.iter().rev().find(|hit| {
                hit.sec < from_sec
                    || (hit.sec == from_sec && hit.para < from_para)
                    || (hit.sec == from_sec && hit.para == from_para && hit.char_offset < from_char)
            });
            Ok(match before {
                Some(hit) => format_search_result(hit, false),
                None => format_search_result(&hits[hits.len() - 1], true),
            })
        }
    }

    pub fn search_text_native(
        &self,
        query: &str,
        from_sec: u32,
        from_para: u32,
        from_char: u32,
        forward: bool,
        case_sensitive: bool,
    ) -> Result<String> {
        self.search_text(
            query,
            from_sec,
            from_para,
            from_char,
            forward,
            case_sensitive,
        )
    }

    pub fn search_all_text(
        &self,
        query: &str,
        case_sensitive: bool,
        _include_cells: bool,
    ) -> String {
        if query.is_empty() {
            return "[]".to_string();
        }

        let hits = self.search_hits(query, case_sensitive);
        let json_hits = hits
            .iter()
            .map(format_search_hit)
            .collect::<Vec<_>>()
            .join(",");
        format!("[{json_hits}]")
    }

