#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ObjectImageSourcePathCandidate {
    length_offset: usize,
    declared_length: usize,
    bytes_start: usize,
    bytes_end: usize,
    nul_terminated: bool,
    bytes: Vec<u8>,
    text_lossy: String,
}

impl ObjectImageSourcePathCandidate {
    pub fn new(
        length_offset: usize,
        declared_length: usize,
        bytes_start: usize,
        bytes_end: usize,
        nul_terminated: bool,
        bytes: Vec<u8>,
    ) -> Self {
        let text_bytes = if nul_terminated && bytes.last() == Some(&0) {
            &bytes[..bytes.len().saturating_sub(1)]
        } else {
            &bytes
        };
        Self {
            length_offset,
            declared_length,
            bytes_start,
            bytes_end,
            nul_terminated,
            text_lossy: String::from_utf8_lossy(text_bytes).into_owned(),
            bytes,
        }
    }

    pub fn length_offset(&self) -> usize {
        self.length_offset
    }

    pub fn declared_length(&self) -> usize {
        self.declared_length
    }

    pub fn bytes_start(&self) -> usize {
        self.bytes_start
    }

    pub fn bytes_end(&self) -> usize {
        self.bytes_end
    }

    pub fn nul_terminated(&self) -> bool {
        self.nul_terminated
    }

    pub fn bytes(&self) -> &[u8] {
        &self.bytes
    }

    pub fn text_lossy(&self) -> &str {
        &self.text_lossy
    }
}

