#[derive(Debug, Clone)]
struct EmbeddedPressTitleArtShadowEffect {
    opacity: f32,
    word0: u32,
    fill_color: String,
}

impl EmbeddedPressTitleArtShadowEffect {
    fn svg_attrs(&self) -> String {
        format!(
            " data-title-shadow-effect-opacity=\"{:.3}\" data-title-shadow-effect-word0=\"0x{:02x}\" data-title-shadow-fill-source=\"embedded-press-0x70-word0-percent-black-on-white\"",
            self.opacity, self.word0
        )
    }
}

fn embedded_press_title_art_shadow_effect(
    shadow_paths: &[&ObjectEmbeddedPressVectorPathCandidate],
) -> Option<EmbeddedPressTitleArtShadowEffect> {
    let word0_values = embedded_press_title_art_state_record_word0_values(shadow_paths, 0x70);
    if word0_values.len() != 1 || word0_values[0] > 100 {
        return None;
    }
    let opacity = word0_values[0] as f32 / 100.0;
    let channel = ((1.0 - opacity) * 255.0).round().clamp(0.0, 255.0) as u8;
    Some(EmbeddedPressTitleArtShadowEffect {
        opacity,
        word0: word0_values[0],
        fill_color: format!("#{channel:02x}{channel:02x}{channel:02x}"),
    })
}

#[allow(clippy::too_many_arguments)]
fn push_success_data_test_title_art_texture_svg(
    svg: &mut String,
    snapshot: &ObjectEmbeddedPressSnapshotCandidate,
    texture_paths: &[&ObjectEmbeddedPressVectorPathCandidate],
    texture_path_source: &str,
    texture_clip_id: &str,
    texture_clip_source: &str,
    x: f32,
    y: f32,
    scale_x: f32,
    scale_y: f32,
) {
    if texture_paths.is_empty() {
        return;
    }

    let texture_header_count = embedded_press_snapshot_texture_bezier_header_count(snapshot);
    let texture_header = embedded_press_snapshot_texture_bezier_header_summary(snapshot);
    let texture_header_homogeneous =
        embedded_press_snapshot_texture_bezier_headers_are_homogeneous(snapshot);
    let effective_shadow_texture_paths =
        success_data_test_title_art_effective_texture_paths_for_word5(
            snapshot,
            EMBEDDED_PRESS_TITLE_ART_SHADOW_STATE_WORD5,
        );
    let effective_texture_state_word5_values =
        success_data_test_title_art_effective_texture_word5_values(snapshot);
    let effective_texture_state_word5_values_attr =
        embedded_press_state_word5_values_attr(&effective_texture_state_word5_values);
    let texture_state_source = if effective_shadow_texture_paths.len() == texture_paths.len() {
        "embedded-press-current-paint-state-inheritance"
    } else {
        "preserved-texture-paths-with-partial-current-state-evidence"
    };
    let texture_source = texture_header.filter(|header| header.flags() == 1).map_or(
        "embedded-press-texture-bezier-filled-source-paths",
        |_| "embedded-press-texture-bezier-flags-1-filled-source-paths",
    );
    let texture_header_attrs = texture_header.map_or_else(String::new, |header| {
        format!(
            " data-texture-bezier-header-count=\"{texture_header_count}\" data-texture-bezier-point-count=\"{}\" data-texture-bezier-byte-count=\"{}\" data-texture-bezier-flags=\"{}\" data-texture-bezier-flags-hex=\"0x{:08x}\" data-texture-bezier-homogeneous=\"{}\"",
            header.point_count(),
            header.byte_count(),
            header.flags(),
            header.flags(),
            texture_header_homogeneous
        )
    });
    svg.push_str(&format!(
        "<g class=\"rjtd-success-data-test-title-art-textures\" clip-path=\"url(#{})\" data-title-layer=\"extrusion-texture\" data-title-compositing=\"shadow-under-front-face\" data-title-texture-path-source=\"{}\" data-title-texture-clip-source=\"{}\" data-texture-path-count=\"{}\" data-title-effective-shadow-texture-path-count=\"{}\" data-title-effective-texture-state-word5-values=\"{}\" data-title-texture-state-source=\"{}\" data-title-texture-rendering=\"filled-source-paths\"{}>",
        escape_xml(texture_clip_id),
        escape_xml(texture_path_source),
        escape_xml(texture_clip_source),
        texture_paths.len(),
        effective_shadow_texture_paths.len(),
        escape_xml(&effective_texture_state_word5_values_attr),
        escape_xml(texture_state_source),
        texture_header_attrs
    ));
    for path in texture_paths {
        push_embedded_press_vector_path_svg(
            svg,
            "rjtd-success-data-test-title-art-texture-path",
            path,
            EmbeddedPressPageContext { x, y, scale_x, scale_y },
            "#111111",
            "nonzero",
            Some(&embedded_press_title_art_state_word5(path).map_or_else(
                || {
                    format!(
                        " data-title-layer=\"extrusion-texture\" data-title-texture-source=\"{texture_source}\""
                    )
                },
                |state_word5| {
                    format!(
                        " data-title-layer=\"extrusion-texture\" data-title-texture-source=\"{texture_source}\" data-title-texture-state-word5=\"0x{state_word5:02x}\""
                    )
                },
            )),
        );
    }
    svg.push_str("</g>");
}

#[allow(clippy::too_many_arguments)]
fn push_success_data_test_title_art_front_texture_svg(
    svg: &mut String,
    snapshot: &ObjectEmbeddedPressSnapshotCandidate,
    texture_clip_id: &str,
    source_paint_candidate: Option<&ObjectJsfartArtPaintCandidate>,
    x: f32,
    y: f32,
    scale_x: f32,
    scale_y: f32,
) {
    let mut texture_paths = success_data_test_title_art_front_texture_paths(snapshot);
    let mut texture_path_source = "main-state-texture-paths";
    let mut texture_rendering = "paint-state-color-filled-source-paths";
    let mut texture_opacity_source = "state-tagged-texture-paths";
    if texture_paths.is_empty() {
        let front_erase_texture_paths =
            success_data_test_title_art_front_erase_texture_paths(snapshot);
        if !front_erase_texture_paths.is_empty() {
            texture_paths = front_erase_texture_paths;
            texture_path_source =
                success_data_test_title_art_front_erase_texture_path_source(&texture_paths)
                    .unwrap_or("interstitial-between-shadow-and-main-outlines");
            texture_rendering = "paint-state-color-front-erase-source-paths";
            texture_opacity_source = "embedded-press-0x82-white-paint-state";
        }
    }
    if texture_paths.is_empty() {
        return;
    }

    let texture_fill = source_paint_candidate
        .and_then(jsfart_paint_candidate_color_hex)
        .or_else(|| embedded_press_snapshot_paint_state_color_hex(snapshot))
        .unwrap_or_else(|| "#ffffff".to_string());
    let texture_header_count = embedded_press_snapshot_texture_bezier_header_count(snapshot);
    let texture_header = embedded_press_snapshot_texture_bezier_header_summary(snapshot);
    let texture_header_homogeneous =
        embedded_press_snapshot_texture_bezier_headers_are_homogeneous(snapshot);
    let texture_state_word5_values = embedded_press_vector_path_state_word5_values(&texture_paths);
    let texture_state_word5_values_attr =
        embedded_press_state_word5_values_attr(&texture_state_word5_values);
    let texture_opacity = if texture_rendering == "paint-state-color-front-erase-source-paths"
        && let Some((opacity, source)) =
            embedded_press_title_art_front_erase_texture_opacity(&texture_paths)
    {
        texture_opacity_source = source;
        opacity
    } else {
        1.0
    };
    let texture_header_attrs = texture_header.map_or_else(String::new, |header| {
        format!(
            " data-texture-bezier-header-count=\"{texture_header_count}\" data-texture-bezier-point-count=\"{}\" data-texture-bezier-byte-count=\"{}\" data-texture-bezier-flags=\"{}\" data-texture-bezier-flags-hex=\"0x{:08x}\" data-texture-bezier-homogeneous=\"{}\"",
            header.point_count(),
            header.byte_count(),
            header.flags(),
            header.flags(),
            texture_header_homogeneous
        )
    });
    svg.push_str(&format!(
        "<g class=\"rjtd-success-data-test-title-art-front-textures\" clip-path=\"url(#{})\" opacity=\"{texture_opacity:.3}\" data-title-layer=\"front-texture\" data-title-compositing=\"source-paint-over-front-face\" data-title-texture-path-source=\"{}\" data-title-texture-clip-source=\"source-main-outline\" data-title-texture-rendering=\"{}\" data-title-texture-paint-color=\"{}\" data-title-texture-opacity=\"{texture_opacity:.3}\" data-title-texture-opacity-source=\"{}\" data-title-texture-state-word5-values=\"{}\" data-texture-path-count=\"{}\"{}>",
        escape_xml(texture_clip_id),
        escape_xml(texture_path_source),
        escape_xml(texture_rendering),
        escape_xml(&texture_fill),
        escape_xml(texture_opacity_source),
        escape_xml(&texture_state_word5_values_attr),
        texture_paths.len(),
        texture_header_attrs
    ));
    for path in texture_paths {
        let texture_source_attr =
            if texture_rendering == "paint-state-color-front-erase-source-paths" {
                "embedded-press-0x82-word3-white-paint"
            } else {
                "embedded-press-paint-state-0x82-word3"
            };
        let extra_attrs = embedded_press_title_art_state_word5(path).map_or_else(
            || {
                format!(
                    " data-title-layer=\"front-texture\" data-title-texture-source=\"{texture_source_attr}\""
                )
            },
            |state_word5| {
                format!(
                    " data-title-layer=\"front-texture\" data-title-texture-source=\"{texture_source_attr}\" data-title-texture-state-word5=\"0x{state_word5:02x}\""
                )
            },
        );
        push_embedded_press_vector_path_svg(
            svg,
            "rjtd-success-data-test-title-art-front-texture-path",
            path,
            EmbeddedPressPageContext { x, y, scale_x, scale_y },
            &texture_fill,
            "nonzero",
            Some(&extra_attrs),
        );
    }
    svg.push_str("</g>");
}

fn success_data_test_title_art_state_tagged_texture_paths(
    snapshot: &ObjectEmbeddedPressSnapshotCandidate,
) -> Vec<&ObjectEmbeddedPressVectorPathCandidate> {
    snapshot
        .vector_paths()
        .iter()
        .filter(|path| {
            path.kind() == ObjectEmbeddedPressVectorPathKind::Texture
                && !path.commands().is_empty()
                && path
                    .state_records()
                    .iter()
                    .any(|record| record.record_type() == EMBEDDED_PRESS_RECORD_PAINT_STATE_82)
        })
        .collect::<Vec<_>>()
}

fn success_data_test_title_art_front_texture_paths(
    snapshot: &ObjectEmbeddedPressSnapshotCandidate,
) -> Vec<&ObjectEmbeddedPressVectorPathCandidate> {
    snapshot
        .vector_paths()
        .iter()
        .filter(|path| {
            path.kind() == ObjectEmbeddedPressVectorPathKind::Texture
                && !path.commands().is_empty()
                && embedded_press_title_art_state_word5(path)
                    == Some(EMBEDDED_PRESS_TITLE_ART_MAIN_STATE_WORD5)
        })
        .collect::<Vec<_>>()
}

fn success_data_test_title_art_front_erase_texture_paths(
    snapshot: &ObjectEmbeddedPressSnapshotCandidate,
) -> Vec<&ObjectEmbeddedPressVectorPathCandidate> {
    if !success_data_test_title_art_front_texture_paths(snapshot).is_empty() {
        return Vec::new();
    }

    let Some(partition) = embedded_press_title_art_shadow_path_partition(snapshot) else {
        return Vec::new();
    };

    let texture_paths =
        success_data_test_title_art_interstitial_texture_paths(snapshot, &partition)
            .unwrap_or_default();
    let explicit_state_texture_paths = texture_paths
        .iter()
        .copied()
        .filter(|path| !path.state_records().is_empty())
        .collect::<Vec<_>>();
    if explicit_state_texture_paths.is_empty() {
        texture_paths
    } else {
        explicit_state_texture_paths
    }
}

