#[allow(clippy::too_many_arguments)]
fn push_embedded_press_vector_path_svg_inner(
    svg: &mut String,
    class_name: &str,
    path: &ObjectEmbeddedPressVectorPathCandidate,
    ctx: EmbeddedPressPageContext,
    source_offset_x: f32,
    source_offset_y: f32,
    fill: &str,
    fill_rule: &str,
    stroke: Option<(&str, f32)>,
    extra_attrs: Option<&str>,
) {
    let EmbeddedPressPageContext { x, y, scale_x, scale_y } = ctx;
    svg.push_str(&format!(
        "<path class=\"{}\" data-path-kind=\"{}\" d=\"",
        escape_xml(class_name),
        path.kind().as_str()
    ));
    for command in path.commands() {
        match command {
            ObjectEmbeddedPressVectorPathCommandCandidate::MoveTo { x: px, y: py } => {
                let page_x = x + (*px as f32 + source_offset_x) * scale_x;
                let page_y = y + (*py as f32 + source_offset_y) * scale_y;
                svg.push_str(&format!("M {page_x:.2} {page_y:.2} "));
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::CubicTo {
                x1,
                y1,
                x2,
                y2,
                x3,
                y3,
            } => {
                let page_x1 = x + (*x1 as f32 + source_offset_x) * scale_x;
                let page_y1 = y + (*y1 as f32 + source_offset_y) * scale_y;
                let page_x2 = x + (*x2 as f32 + source_offset_x) * scale_x;
                let page_y2 = y + (*y2 as f32 + source_offset_y) * scale_y;
                let page_x3 = x + (*x3 as f32 + source_offset_x) * scale_x;
                let page_y3 = y + (*y3 as f32 + source_offset_y) * scale_y;
                svg.push_str(&format!(
                    "C {page_x1:.2} {page_y1:.2}, {page_x2:.2} {page_y2:.2}, {page_x3:.2} {page_y3:.2} "
                ));
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::Close => {
                svg.push_str("Z ");
            }
        }
    }
    let stroke_attrs = if let Some((stroke, stroke_width)) =
        stroke.filter(|(_, width)| *width > 0.0)
    {
        format!(
            "\" fill=\"{}\" stroke=\"{}\" stroke-width=\"{stroke_width:.2}\" stroke-linejoin=\"round\" stroke-linecap=\"round\" fill-rule=\"{}\"{}",
            escape_xml(fill),
            escape_xml(stroke),
            escape_xml(fill_rule),
            extra_attrs.unwrap_or("")
        )
    } else {
        format!(
            "\" fill=\"{}\" stroke=\"none\" fill-rule=\"{}\"{}",
            escape_xml(fill),
            escape_xml(fill_rule),
            extra_attrs.unwrap_or("")
        )
    };
    svg.push_str(&format!("{stroke_attrs}/>"));
}

fn embedded_press_vector_path_data(
    path: &ObjectEmbeddedPressVectorPathCandidate,
    x: f32,
    y: f32,
    scale_x: f32,
    scale_y: f32,
) -> Option<String> {
    embedded_press_vector_path_data_with_source_offset(path, x, y, scale_x, scale_y, 0.0, 0.0)
}

fn embedded_press_vector_path_data_with_source_offset(
    path: &ObjectEmbeddedPressVectorPathCandidate,
    x: f32,
    y: f32,
    scale_x: f32,
    scale_y: f32,
    source_offset_x: f32,
    source_offset_y: f32,
) -> Option<String> {
    if path.commands().is_empty() {
        return None;
    }

    let mut path_data = String::new();
    for command in path.commands() {
        match command {
            ObjectEmbeddedPressVectorPathCommandCandidate::MoveTo { x: px, y: py } => {
                let page_x = x + (*px as f32 + source_offset_x) * scale_x;
                let page_y = y + (*py as f32 + source_offset_y) * scale_y;
                path_data.push_str(&format!("M {page_x:.2} {page_y:.2} "));
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::CubicTo {
                x1,
                y1,
                x2,
                y2,
                x3,
                y3,
            } => {
                let page_x1 = x + (*x1 as f32 + source_offset_x) * scale_x;
                let page_y1 = y + (*y1 as f32 + source_offset_y) * scale_y;
                let page_x2 = x + (*x2 as f32 + source_offset_x) * scale_x;
                let page_y2 = y + (*y2 as f32 + source_offset_y) * scale_y;
                let page_x3 = x + (*x3 as f32 + source_offset_x) * scale_x;
                let page_y3 = y + (*y3 as f32 + source_offset_y) * scale_y;
                path_data.push_str(&format!(
                    "C {page_x1:.2} {page_y1:.2}, {page_x2:.2} {page_y2:.2}, {page_x3:.2} {page_y3:.2} "
                ));
            }
            ObjectEmbeddedPressVectorPathCommandCandidate::Close => {
                path_data.push_str("Z ");
            }
        }
    }
    (!path_data.is_empty()).then_some(path_data)
}

fn push_embedded_press_snapshot_vector_svg(
    svg: &mut String,
    x: f32,
    y: f32,
    width: f32,
    height: f32,
    diagnostic: EmbeddingFrameDiagnostic<'_>,
    snapshot: &ObjectEmbeddedPressSnapshotCandidate,
) {
    if snapshot.vector_segments().is_empty() || snapshot.width() == 0 || snapshot.height() == 0 {
        return;
    }
    let scale_x = width / snapshot.width() as f32;
    let scale_y = height / snapshot.height() as f32;
    svg.push_str(&format!(
        "<g class=\"rjtd-embedded-press-snapshot-vector\" data-projection=\"embeddedPressSnapshotVectorProjection\" data-embedding-index=\"{}\" data-vector-segment-count=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\">",
        diagnostic.frame.embedding_index(),
        snapshot.vector_segments().len()
    ));
    for segment in snapshot.vector_segments() {
        let x1 = x + segment.x1() as f32 * scale_x;
        let y1 = y + segment.y1() as f32 * scale_y;
        let x2 = x + segment.x2() as f32 * scale_x;
        let y2 = y + segment.y2() as f32 * scale_y;
        svg.push_str(&format!(
            "<line x1=\"{x1:.2}\" y1=\"{y1:.2}\" x2=\"{x2:.2}\" y2=\"{y2:.2}\" stroke=\"#111111\" stroke-width=\"0.42\" stroke-linecap=\"round\"/>"
        ));
    }
    svg.push_str("</g>");
}

fn visual_list_horizontal_run_height(scale_y: f32) -> f32 {
    (scale_y * 0.38).clamp(0.9, 1.8)
}

fn push_layout_box_text_projection_svg(
    svg: &mut String,
    projection: &LayoutBoxTextProjection,
    font_family: &str,
) {
    svg.push_str(&format!(
        "<g class=\"rjtd-layout-box-text-projection\" data-source=\"{}\" data-projection-kind=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-page-assignment-decoded=\"{}\" data-block-count=\"{}\" data-layout-record-count=\"{}\" data-position-table-present=\"{}\">",
        escape_xml(projection.source),
        escape_xml(projection.projection_kind),
        projection.page_assignment_decoded,
        projection.block_count,
        projection.layout_record_count,
        projection.position_table_present
    ));
    for slot in &projection.slots {
        let record_index = slot
            .layout_record_index
            .map(|index| index.to_string())
            .unwrap_or_else(|| "-".to_string());
        svg.push_str(&format!(
            "<text class=\"rjtd-text rjtd-layout-box-text\" data-source=\"{}\" data-role=\"{}\" data-block-index=\"{}\" data-layout-record-index=\"{}\" data-placement-basis=\"{}\" x=\"{:.1}\" y=\"{:.1}\" font-family=\"{}\" font-size=\"{:.1}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
            escape_xml(projection.source),
            escape_xml(slot.role),
            slot.block_index,
            escape_xml(&record_index),
            escape_xml(slot.placement_basis),
            slot.x,
            slot.y + slot.font_size,
            font_family,
            slot.font_size,
            escape_xml(&svg_visual_text(&slot.text))
        ));
    }
    svg.push_str("</g>");
}

fn push_page_frame_projection_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
) {
    let Some(projection) = page_frame_projection(document, layout, page_number) else {
        return;
    };

    let pattern_id = format!("rjtd-page-frame-pattern-{page_number}");
    svg.push_str(&format!(
        "<defs><pattern id=\"{}\" width=\"5\" height=\"5\" patternUnits=\"userSpaceOnUse\"><rect width=\"5\" height=\"5\" fill=\"#fbfbfb\"/><circle cx=\"1.4\" cy=\"1.4\" r=\"{:.2}\" fill=\"#d1d1d1\"/><circle cx=\"3.9\" cy=\"3.9\" r=\"{:.2}\" fill=\"#d1d1d1\"/></pattern></defs>",
        escape_xml(&pattern_id),
        PAGE_FRAME_PATTERN_DOT_RADIUS_PX,
        PAGE_FRAME_PATTERN_DOT_RADIUS_PX
    ));
    svg.push_str(&format!(
        "<g class=\"rjtd-page-frame-projection\" data-source=\"{}\" data-projection-kind=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-style-decoded=\"false\" data-placement-proven=\"true\" data-page-assignment-decoded=\"{}\" data-record-count=\"{}\">",
        escape_xml(projection.source),
        escape_xml(projection.projection_kind),
        projection.page_assignment_decoded,
        projection.record_count
    ));
    for shape in &projection.shapes {
        match shape.role {
            "titleRoundedFrame" => {
                push_title_rounded_frame_svg(svg, shape);
            }
            "horizontalPatternBar" => {
                push_horizontal_pattern_bar_svg(svg, shape, &pattern_id);
            }
            _ => {}
        }
    }
    svg.push_str("</g>");
}

