fn push_observed_form_text_projection_svg(
    svg: &mut String,
    projection: &ObservedFormTextProjection,
    _font_family: &str,
) {
    svg.push_str(&format!(
        "<g class=\"rjtd-observed-form-text-projection\" data-source=\"{}\" data-projection=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"true\">",
        escape_xml(projection.source),
        escape_xml(projection.projection_kind)
    ));
    for shape in &projection.shapes {
        let stroke = shape.stroke.unwrap_or("none");
        svg.push_str(&format!(
            "<rect class=\"rjtd-form-shape\" data-role=\"{}\" x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" rx=\"{:.1}\" ry=\"{:.1}\" fill=\"{}\" stroke=\"{}\" stroke-width=\"{:.1}\"/>",
            escape_xml(shape.role),
            shape.x,
            shape.y,
            shape.width,
            shape.height,
            shape.rx,
            shape.rx,
            escape_xml(shape.fill),
            escape_xml(stroke),
            shape.stroke_width
        ));
    }
    for slot in &projection.slots {
        let anchor = slot.anchor;
        let text = escape_xml(&svg_visual_text(&slot.text));
        let font_family = escape_xml(slot.font_family);
        svg.push_str(&format!(
            "<text class=\"rjtd-form-text\" data-role=\"{}\" x=\"{:.1}\" y=\"{:.1}\" text-anchor=\"{}\" font-family=\"{}\" font-size=\"{:.1}\" font-weight=\"{}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
            escape_xml(slot.role),
            slot.x,
            slot.y,
            anchor,
            font_family,
            slot.font_size,
            slot.font_weight,
            text
        ));
    }
    svg.push_str("</g>");
}

fn push_success_data_test_top_text_projection_svg(
    svg: &mut String,
    document: &Document,
    slots: &[SuccessDataTestTextSlot],
    font_family: &str,
) {
    svg.push_str("<g class=\"rjtd-success-data-test-top-text-projection\" data-projection-kind=\"successDataTestTopTextProjection\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-reference-backed=\"true\">");
    let figure_label_line = success_data_test_q4_figure_label_source_line(document, slots);
    for slot in slots {
        if figure_label_line.is_some() && slot.role == "figure-label" {
            continue;
        }
        svg.push_str(&format!(
            "<g class=\"rjtd-success-data-test-top-text-slot\" data-role=\"{}\">",
            escape_xml(slot.role)
        ));
        push_svg_text_run(
            svg,
            "rjtd-success-data-test-top-text",
            slot.x,
            slot.y + SUCCESS_DATA_TEST_TOP_TEXT_FONT_SIZE_PX,
            font_family,
            SUCCESS_DATA_TEST_TOP_TEXT_FONT_SIZE_PX,
            "#111111",
            slot.text,
            None,
        );
        svg.push_str("</g>");
    }
    if let Some(line) = figure_label_line {
        svg.push_str(
            "<g class=\"rjtd-success-data-test-top-text-slot\" data-role=\"figure-label-line\">",
        );
        svg.push_str(&format!(
            "<metadata data-render-source=\"document-text-preserved-spacing\" data-line-text=\"{}\" data-source-byte-start=\"{}\" data-source-byte-end=\"{}\" data-source-unit-start=\"{}\" data-source-unit-end=\"{}\" data-advance-model=\"japanese-fixed-pitch-halfwidth-space\" data-origin-x=\"{:.1}\" data-font-size=\"{:.1}\"/>",
            escape_xml(&line.text),
            line.source_span.byte_start,
            line.source_span.byte_end,
            line.source_span.unit_start,
            line.source_span.unit_end,
            line.x,
            line.font_size,
        ));
        for span in &line.spans {
            svg.push_str(&format!(
                "<text class=\"rjtd-success-data-test-top-text\" data-role=\"figure-label\" data-render-source=\"document-text-fixed-pitch-span\" data-source-byte-start=\"{}\" data-source-byte-end=\"{}\" data-source-unit-start=\"{}\" data-source-unit-end=\"{}\" x=\"{:.1}\" y=\"{:.1}\" font-family=\"{}\" font-size=\"{:.1}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
                span.source_span.byte_start,
                span.source_span.byte_end,
                span.source_span.unit_start,
                span.source_span.unit_end,
                span.x,
                line.y + line.font_size,
            escape_xml(font_family),
                line.font_size,
                escape_xml(&svg_visual_text(&span.text))
            ));
        }
        svg.push_str("</g>");
    }
    svg.push_str("</g>");
}

#[derive(Debug, Clone)]
struct SuccessDataTestFigureLabelLine {
    text: String,
    x: f32,
    y: f32,
    font_size: f32,
    source_span: TextSourceSpan,
    line_header: Option<ShanaiLanLineHeader>,
    spans: Vec<SuccessDataTestFigureLabelSpan>,
}

#[derive(Debug, Clone)]
struct SuccessDataTestFigureLabelSpan {
    text: String,
    x: f32,
    source_span: TextSourceSpan,
}

fn success_data_test_q4_figure_label_source_line(
    document: &Document,
    slots: &[SuccessDataTestTextSlot],
) -> Option<SuccessDataTestFigureLabelLine> {
    let heading = slots
        .iter()
        .find(|slot| slot.text.starts_with("４、次の図で"))?;
    let line_step = success_data_test_top_text_line_step_px(slots)?;
    let bytes = document_text_raw_stream(document)?;
    let map = map_document_text(bytes);
    let entry = map
        .entries()
        .iter()
        .find(|entry| success_data_test_q4_figure_label_text_line(entry.text()))?;
    let text = entry.text().trim_end_matches('\n').to_string();
    let y = heading.y + line_step;
    let font_size = success_data_test_figure_label_font_size_px(line_step);
    let source_span = TextSourceSpan::from_document_text_entry(entry);
    let spans = success_data_test_q4_figure_label_spans(&text, heading.x, font_size, &source_span)?;
    Some(SuccessDataTestFigureLabelLine {
        text,
        x: heading.x,
        y,
        font_size,
        source_span,
        line_header: shanai_lan_line_header_for_text_entry(bytes, entry),
        spans,
    })
}

fn success_data_test_q4_figure_label_text_line(text: &str) -> bool {
    let line = text.trim_end_matches('\n');
    if !(line.contains("（１）") && line.contains("（２）") && line.contains("（３）")) {
        return false;
    }
    line.chars()
        .all(|character| matches!(character, ' ' | '（' | '）' | '１' | '２' | '３'))
}

fn success_data_test_top_text_line_step_px(slots: &[SuccessDataTestTextSlot]) -> Option<f32> {
    let mut deltas = slots
        .windows(2)
        .filter_map(|window| {
            let delta = window[1].y - window[0].y;
            (18.0..=24.0).contains(&delta).then_some(delta)
        })
        .collect::<Vec<_>>();
    if deltas.is_empty() {
        return None;
    }
    deltas.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    deltas.get(deltas.len() / 2).copied()
}

fn success_data_test_figure_label_font_size_px(line_step: f32) -> f32 {
    (line_step * 2.0 / 3.0).max(SUCCESS_DATA_TEST_TOP_TEXT_FONT_SIZE_PX)
}

fn success_data_test_q4_figure_label_spans(
    line_text: &str,
    origin_x: f32,
    font_size: f32,
    source_span: &TextSourceSpan,
) -> Option<Vec<SuccessDataTestFigureLabelSpan>> {
    let mut cursor_units = 0usize;
    ["（１）", "（２）", "（３）"]
        .iter()
        .map(|label| {
            let (start_units, end_units) =
                find_text_utf16_unit_range_after(line_text, label, cursor_units)?;
            cursor_units = end_units;
            let start_byte = byte_index_after_utf16_units(line_text, start_units)?;
            let prefix = &line_text[..start_byte];
            Some(SuccessDataTestFigureLabelSpan {
                text: (*label).to_string(),
                x: origin_x + success_data_test_fixed_pitch_advance_px(prefix, font_size),
                source_span: source_span.subspan_by_units(start_units, end_units),
            })
        })
        .collect()
}

fn success_data_test_fixed_pitch_advance_px(text: &str, font_size: f32) -> f32 {
    text.chars()
        .map(|character| {
            if character == ' ' || character.is_ascii() {
                font_size * 0.5
            } else {
                font_size
            }
        })
        .sum()
}

fn push_success_data_test_cone_diagram_projection_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
    font_family: &str,
) {
    if page_number != 1 || !document_has_success_data_test_projection_evidence(document) {
        return;
    }
    let Some(candidate) = document
        .object_stream_candidates()
        .iter()
        .find(|candidate| candidate.path() == "/FigureData/main_data/FDMVector")
    else {
        return;
    };
    let fdm_text_source = document
        .object_stream_candidates()
        .iter()
        .find(|candidate| candidate.path() == "/FigureData/main_data/FDMText");
    let fdm_text_candidates = fdm_text_source
        .map(ObjectStreamCandidate::fdm_text_candidates)
        .unwrap_or(&[]);
    let Some(cone_projection) = success_data_test_cone_fdm_projection_from_segments(
        candidate.fdm_raw_vector_segments(),
        fdm_text_candidates,
    ) else {
        return;
    };
    let raw_commands = candidate.fdm_raw_vector_commands();
    let fdm_text_source_path = fdm_text_source
        .map(ObjectStreamCandidate::path)
        .unwrap_or("/FigureData/main_data/FDMText");
    let commands = raw_commands
        .iter()
        .filter(|command| success_data_test_cone_vector_command(cone_projection, command))
        .collect::<Vec<_>>();
    if commands.is_empty() {
        return;
    }

    svg.push_str(&format!(
        "<g class=\"rjtd-success-data-test-cone-diagram\" data-source-path=\"{}\" data-projection=\"successDataTestFdmConeProjection\" data-source-left=\"{}\" data-source-top=\"{}\" data-source-right=\"{}\" data-source-bottom=\"{}\" data-reference-backed=\"true\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\" data-renderable=\"true\" data-raw-vector-command-count=\"{}\">",
        escape_xml(candidate.path()),
        cone_projection.source_left,
        cone_projection.source_top,
        cone_projection.source_right,
        cone_projection.source_bottom,
        candidate.fdm_raw_vector_commands().len()
    ));
    for &command in &commands {
        if let Some(ellipse) = command.ellipse() {
            let Some((cx, cy, rx, ry)) =
                success_data_test_projected_fdm_ellipse(layout, cone_projection, ellipse)
            else {
                continue;
            };
            svg.push_str(&format!(
                "<ellipse class=\"rjtd-success-data-test-cone-primitive\" data-primitive-kind=\"ellipse\" data-relative-offset=\"{}\" cx=\"{cx:.1}\" cy=\"{cy:.1}\" rx=\"{rx:.1}\" ry=\"{ry:.1}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"0.85\"/>",
                command.relative_offset()
            ));
            continue;
        }
        let Some(path_data) =
            success_data_test_projected_fdm_path_data(layout, cone_projection, command)
        else {
            continue;
        };
        let dash = if success_data_test_cone_command_is_dashed(command) {
            " stroke-dasharray=\"4 4\""
        } else {
            ""
        };
        svg.push_str(&format!(
            "<path class=\"rjtd-success-data-test-cone-primitive\" data-primitive-kind=\"{}\" data-marker-hex=\"{}\" data-style-word=\"0x{:04x}\" data-relative-offset=\"{}\" d=\"{}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"0.85\" stroke-linecap=\"round\" stroke-linejoin=\"round\"{dash}/>",
            fdm_vector_primitive_kind(command),
            hex_bytes(command.marker()),
            command.style_word(),
            command.relative_offset(),
            path_data
        ));
    }
    push_success_data_test_fdm_text_projection_svg(
        svg,
        layout,
        cone_projection,
        fdm_text_source_path,
        fdm_text_candidates,
        font_family,
    );
    svg.push_str("</g>");

    for projection in success_data_test_fdm_reference_projections(candidate) {
        push_success_data_test_fdm_reference_projection_svg(
            svg,
            layout,
            candidate.path(),
            raw_commands,
            projection,
            fdm_text_source_path,
            fdm_text_candidates,
            font_family,
        );
    }
}

fn success_data_test_fdm_reference_projections(
    candidate: &ObjectStreamCandidate,
) -> Vec<SuccessDataTestFdmProjection> {
    let q4_target_height_px = success_data_test_uniform_target_height_px(
        SUCCESS_DATA_TEST_Q4_SOURCE_LEFT,
        SUCCESS_DATA_TEST_Q4_SOURCE_TOP,
        SUCCESS_DATA_TEST_Q4_SOURCE_RIGHT,
        SUCCESS_DATA_TEST_Q4_SOURCE_BOTTOM,
        SUCCESS_DATA_TEST_Q4_TARGET_WIDTH_PX,
    );
    let mut projections = vec![SuccessDataTestFdmProjection {
        role: "q4-angle-diagrams",
        source_left: SUCCESS_DATA_TEST_Q4_SOURCE_LEFT,
        source_top: SUCCESS_DATA_TEST_Q4_SOURCE_TOP,
        source_right: SUCCESS_DATA_TEST_Q4_SOURCE_RIGHT,
        source_bottom: SUCCESS_DATA_TEST_Q4_SOURCE_BOTTOM,
        target_x_px: SUCCESS_DATA_TEST_Q4_TARGET_X_PX,
        target_y_px: SUCCESS_DATA_TEST_Q4_TARGET_Y_PX,
        target_width_px: SUCCESS_DATA_TEST_Q4_TARGET_WIDTH_PX,
        target_height_px: q4_target_height_px,
        scale_mode: SuccessDataTestFdmScaleMode::UniformUnitsFromHorizontalSpan,
    }];
    if let Some(q5_projection) =
        success_data_test_q5_fdm_projection_from_segments(candidate.fdm_raw_vector_segments())
    {
        projections.push(q5_projection);
    }
    projections
}

fn success_data_test_cone_fdm_projection_from_segments(
    segments: &[ObjectFdmVectorSegmentCandidate],
    text_candidates: &[ObjectFdmTextCandidate],
) -> Option<SuccessDataTestFdmProjection> {
    let segment = segments.iter().find(|segment| {
        segment.source_width() > 0 && segment.source_height() > 0 && segment.bbox().is_some()
    })?;
    let vector_bbox = segment.bbox().map(normalize_fdm_bbox)?;
    let bbox = text_candidates
        .iter()
        .filter_map(|candidate| candidate.bbox().map(normalize_fdm_bbox))
        .filter(|bbox| success_data_test_cone_text_bbox_matches_vector_bbox(vector_bbox, *bbox))
        .fold(Some(vector_bbox), fdm_bbox_extent_union)?;
    Some(SuccessDataTestFdmProjection {
        role: "q3-cone-diagram",
        source_left: bbox.0,
        source_top: bbox.1,
        source_right: bbox.2,
        source_bottom: bbox.3,
        target_x_px: SUCCESS_DATA_TEST_CONE_TARGET_X_PX,
        target_y_px: SUCCESS_DATA_TEST_CONE_TARGET_Y_PX,
        target_width_px: SUCCESS_DATA_TEST_CONE_TARGET_WIDTH_PX,
        target_height_px: SUCCESS_DATA_TEST_CONE_TARGET_HEIGHT_PX,
        scale_mode: SuccessDataTestFdmScaleMode::IndependentReferenceBox,
    })
}

fn success_data_test_uniform_target_height_px(
    source_left: i32,
    source_top: i32,
    source_right: i32,
    source_bottom: i32,
    target_width_px: f32,
) -> f32 {
    let source_width = source_right.saturating_sub(source_left).abs().max(1) as f32;
    let source_height = source_bottom.saturating_sub(source_top).abs().max(1) as f32;
    source_height / source_width * target_width_px
}

fn success_data_test_cone_text_bbox_matches_vector_bbox(
    vector_bbox: (i32, i32, i32, i32),
    text_bbox: (i32, i32, i32, i32),
) -> bool {
    let center_x = text_bbox.0 + (text_bbox.2 - text_bbox.0) / 2;
    let center_y = text_bbox.1 + (text_bbox.3 - text_bbox.1) / 2;
    let width = vector_bbox.2.saturating_sub(vector_bbox.0).abs().max(1);
    let height = vector_bbox.3.saturating_sub(vector_bbox.1).abs().max(1);
    let margin_x = (width / 12).max(16);
    let margin_y = (height / 12).max(16);
    center_x >= vector_bbox.0 - margin_x
        && center_x <= vector_bbox.2 + margin_x
        && center_y >= vector_bbox.1 - margin_y
        && center_y <= vector_bbox.3 + margin_y
}

fn success_data_test_q5_fdm_projection_from_segments(
    segments: &[ObjectFdmVectorSegmentCandidate],
) -> Option<SuccessDataTestFdmProjection> {
    let nonzero_span_segments = segments
        .iter()
        .filter(|segment| {
            segment.source_width() > 0 && segment.source_height() > 0 && segment.bbox().is_some()
        })
        .collect::<Vec<_>>();
    if nonzero_span_segments.len() < 2 {
        return None;
    }

    let first_offset = nonzero_span_segments.first()?.relative_offset();
    let mut selected = nonzero_span_segments
        .iter()
        .copied()
        .filter(|segment| segment.relative_offset() != first_offset);
    let first = selected.next()?;
    let first_bbox = first.bbox().map(normalize_fdm_bbox)?;
    let (mut left, mut top, mut right, mut bottom) = first_bbox;
    for segment in selected {
        let bbox = segment.bbox().map(normalize_fdm_bbox)?;
        left = left.min(bbox.0);
        top = top.min(bbox.1);
        right = right.max(bbox.2);
        bottom = bottom.max(bbox.3);
    }

    Some(SuccessDataTestFdmProjection {
        role: "q5-solid-diagram",
        source_left: left,
        source_top: top,
        source_right: right,
        source_bottom: bottom,
        target_x_px: SUCCESS_DATA_TEST_Q5_TARGET_X_PX,
        target_y_px: SUCCESS_DATA_TEST_Q5_TARGET_Y_PX,
        target_width_px: SUCCESS_DATA_TEST_Q5_TARGET_WIDTH_PX,
        target_height_px: SUCCESS_DATA_TEST_Q5_TARGET_HEIGHT_PX,
        scale_mode: SuccessDataTestFdmScaleMode::IndependentReferenceBox,
    })
}

#[allow(clippy::too_many_arguments)]
fn push_success_data_test_fdm_reference_projection_svg(
    svg: &mut String,
    layout: PageLayout,
    source_path: &str,
    commands: &[ObjectFdmVectorCommandCandidate],
    projection: SuccessDataTestFdmProjection,
    text_source_path: &str,
    text_candidates: &[ObjectFdmTextCandidate],
    font_family: &str,
) {
    let commands = commands
        .iter()
        .filter(|command| success_data_test_fdm_projection_command(projection, command))
        .collect::<Vec<_>>();
    if commands.is_empty() {
        return;
    }

    svg.push_str(&format!(
        "<g class=\"rjtd-success-data-test-fdm-reference-projection\" data-role=\"{}\" data-source-path=\"{}\" data-projection=\"successDataTestFdmReferenceProjection\" data-source-left=\"{}\" data-source-top=\"{}\" data-source-right=\"{}\" data-source-bottom=\"{}\" data-scale-mode=\"{}\" data-reference-backed=\"true\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\" data-renderable=\"true\" data-command-count=\"{}\">",
        escape_xml(projection.role),
        escape_xml(source_path),
        projection.source_left,
        projection.source_top,
        projection.source_right,
        projection.source_bottom,
        projection.scale_mode.as_str(),
        commands.len()
    ));
    if let Some(subdiagrams) = success_data_test_q4_fdm_subdiagrams(projection, &commands) {
        for subdiagram in &subdiagrams {
            svg.push_str(&format!(
                "<g class=\"rjtd-success-data-test-fdm-subdiagram\" data-role=\"{}\" data-grouping-source=\"nearest-main-circle-source-center\" data-grouping-decoded=\"false\" data-paint-order-decoded=\"false\" data-subdiagram-index=\"{}\" data-anchor-relative-offset=\"{}\" data-anchor-source-x=\"{}\" data-anchor-source-y=\"{}\" data-command-count=\"{}\">",
                escape_xml(projection.role),
                subdiagram.index,
                subdiagram.anchor_relative_offset,
                subdiagram.center.x(),
                subdiagram.center.y(),
                subdiagram.commands.len()
            ));
            for &command in &subdiagram.commands {
                push_success_data_test_fdm_reference_command_svg(
                    svg,
                    layout,
                    projection,
                    &subdiagram.commands,
                    command,
                );
            }
            svg.push_str("</g>");
        }
    } else {
        for &command in &commands {
            push_success_data_test_fdm_reference_command_svg(
                svg, layout, projection, &commands, command,
            );
        }
    }
    push_success_data_test_fdm_text_projection_svg(
        svg,
        layout,
        projection,
        text_source_path,
        text_candidates,
        font_family,
    );
    svg.push_str("</g>");
}

fn push_success_data_test_fdm_reference_command_svg(
    svg: &mut String,
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    local_commands: &[&ObjectFdmVectorCommandCandidate],
    command: &ObjectFdmVectorCommandCandidate,
) {
    let stroke_width = fdm_vector_stroke_width(command);
    if let Some(ellipse) = command.ellipse() {
        if success_data_test_fdm_reference_ellipse_is_control_marker(projection, command, ellipse) {
            let Some(path_data) = success_data_test_projected_fdm_control_ellipse_arc_path_data(
                layout,
                projection,
                ellipse,
                local_commands,
            ) else {
                return;
            };
            svg.push_str(&format!(
                "<path class=\"rjtd-success-data-test-fdm-primitive\" data-role=\"{}\" data-primitive-kind=\"ellipseArc\" data-marker-hex=\"{}\" data-relative-offset=\"{}\" data-render-source=\"q4-small-ellipse-angle-arc\" data-stroke-width-source=\"fdm-vector-style\" data-stroke-width=\"{stroke_width:.3}\" data-local-command-scope=\"source-main-circle-subdiagram\" d=\"{}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>",
                escape_xml(projection.role),
                hex_bytes(command.marker()),
                command.relative_offset(),
                path_data
            ));
            return;
        }
        let Some((cx, cy, rx, ry)) =
            success_data_test_projected_fdm_ellipse(layout, projection, ellipse)
        else {
            return;
        };
        svg.push_str(&format!(
            "<ellipse class=\"rjtd-success-data-test-fdm-primitive\" data-role=\"{}\" data-primitive-kind=\"ellipse\" data-marker-hex=\"{}\" data-relative-offset=\"{}\" data-stroke-width-source=\"fdm-vector-style\" data-stroke-width=\"{stroke_width:.3}\" cx=\"{cx:.1}\" cy=\"{cy:.1}\" rx=\"{rx:.1}\" ry=\"{ry:.1}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\"/>",
            escape_xml(projection.role),
            hex_bytes(command.marker()),
            command.relative_offset()
        ));
        if success_data_test_fdm_reference_ellipse_has_center_marker(projection, command, ellipse) {
            let (dot_cx, dot_cy) = success_data_test_projected_fdm_center_marker_point(
                layout,
                projection,
                ellipse,
                local_commands,
            )
            .unwrap_or((cx, cy));
            let dot_radius = (stroke_width * 3.0).clamp(1.8, 2.6);
            svg.push_str(&format!(
                "<circle class=\"rjtd-success-data-test-fdm-primitive\" data-role=\"{}\" data-primitive-kind=\"centerPoint\" data-marker-hex=\"{}\" data-relative-offset=\"{}\" data-render-source=\"q4-main-circle-center-nearby-line-endpoint\" data-local-command-scope=\"source-main-circle-subdiagram\" data-dot-radius-source=\"fdm-vector-stroke-width\" cx=\"{dot_cx:.1}\" cy=\"{dot_cy:.1}\" r=\"{dot_radius:.1}\" fill=\"#111111\" stroke=\"none\"/>",
                escape_xml(projection.role),
                hex_bytes(command.marker()),
                command.relative_offset()
            ));
        }
        return;
    }

    let Some(path_data) = success_data_test_projected_fdm_path_data(layout, projection, command)
    else {
        return;
    };
    svg.push_str(&format!(
        "<path class=\"rjtd-success-data-test-fdm-primitive\" data-role=\"{}\" data-primitive-kind=\"{}\" data-marker-hex=\"{}\" data-relative-offset=\"{}\" data-stroke-width-source=\"fdm-vector-style\" data-stroke-width=\"{stroke_width:.3}\" d=\"{}\" fill=\"none\" stroke=\"#111111\" stroke-width=\"{stroke_width:.2}\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>",
        escape_xml(projection.role),
        fdm_vector_primitive_kind(command),
        hex_bytes(command.marker()),
        command.relative_offset(),
        path_data
    ));
}

#[derive(Debug)]
struct SuccessDataTestFdmSubdiagram<'a> {
    index: usize,
    anchor_relative_offset: usize,
    center: ObjectFdmVectorPoint,
    commands: Vec<&'a ObjectFdmVectorCommandCandidate>,
}

fn success_data_test_q4_fdm_subdiagrams<'a>(
    projection: SuccessDataTestFdmProjection,
    commands: &[&'a ObjectFdmVectorCommandCandidate],
) -> Option<Vec<SuccessDataTestFdmSubdiagram<'a>>> {
    if projection.role != "q4-angle-diagrams" {
        return None;
    }
    let mut subdiagrams = commands
        .iter()
        .filter_map(|&command| {
            let ellipse = command.ellipse()?;
            success_data_test_fdm_reference_ellipse_has_center_marker(projection, command, ellipse)
                .then(|| SuccessDataTestFdmSubdiagram {
                    index: 0,
                    anchor_relative_offset: command.relative_offset(),
                    center: ellipse.center(),
                    commands: Vec::new(),
                })
        })
        .collect::<Vec<_>>();
    if subdiagrams.len() < 2 {
        return None;
    }
    subdiagrams.sort_by_key(|subdiagram| {
        (
            subdiagram.center.x(),
            subdiagram.center.y(),
            subdiagram.anchor_relative_offset,
        )
    });
    for (index, subdiagram) in subdiagrams.iter_mut().enumerate() {
        subdiagram.index = index;
    }

    for &command in commands {
        let Some(center) = success_data_test_fdm_command_source_center(command) else {
            continue;
        };
        let Some((group_index, _)) = subdiagrams
            .iter()
            .enumerate()
            .map(|(index, subdiagram)| {
                (index, fdm_point_distance_squared(center, subdiagram.center))
            })
            .min_by_key(|(_, distance)| *distance)
        else {
            continue;
        };
        subdiagrams[group_index].commands.push(command);
    }

    subdiagrams
        .iter()
        .all(|subdiagram| !subdiagram.commands.is_empty())
        .then_some(subdiagrams)
}

fn success_data_test_fdm_command_source_center(
    command: &ObjectFdmVectorCommandCandidate,
) -> Option<ObjectFdmVectorPoint> {
    if let Some(ellipse) = command.ellipse() {
        return Some(ellipse.center());
    }
    let bbox = fdm_vector_command_source_bbox(command).map(normalize_fdm_bbox)?;
    Some(ObjectFdmVectorPoint::new(
        bbox.0 + (bbox.2 - bbox.0) / 2,
        bbox.1 + (bbox.3 - bbox.1) / 2,
    ))
}

fn success_data_test_fdm_reference_ellipse_is_control_marker(
    projection: SuccessDataTestFdmProjection,
    command: &ObjectFdmVectorCommandCandidate,
    ellipse: ObjectFdmVectorEllipse,
) -> bool {
    if projection.role != "q4-angle-diagrams" || command.marker() != b"\xff\x00\x04\x60" {
        return false;
    }
    let source_height = projection
        .source_bottom
        .saturating_sub(projection.source_top)
        .abs()
        .max(1);
    ellipse.radius_x() == ellipse.radius_y()
        && ellipse.radius_x().saturating_mul(6) <= source_height
}

fn success_data_test_fdm_reference_ellipse_has_center_marker(
    projection: SuccessDataTestFdmProjection,
    command: &ObjectFdmVectorCommandCandidate,
    ellipse: ObjectFdmVectorEllipse,
) -> bool {
    if projection.role != "q4-angle-diagrams" || command.marker() != b"\x01\x00\x04\x60" {
        return false;
    }
    let source_height = projection
        .source_bottom
        .saturating_sub(projection.source_top)
        .abs()
        .max(1);
    ellipse.radius_x() == ellipse.radius_y()
        && ellipse.radius_x().saturating_mul(2) >= source_height.saturating_mul(4) / 5
}

fn success_data_test_projected_fdm_center_marker_point(
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    ellipse: ObjectFdmVectorEllipse,
    commands: &[&ObjectFdmVectorCommandCandidate],
) -> Option<(f32, f32)> {
    let center = ellipse.center();
    let proximity = (ellipse.radius_x() / 20).max(16) as f32;
    let mut candidates = Vec::new();
    for command in commands {
        if command.ellipse().is_some() {
            continue;
        }
        for point in command.path_points() {
            if fdm_point_distance(center, *point) <= proximity {
                candidates.push(*point);
            }
        }
    }
    if candidates.is_empty() {
        return None;
    }
    let sum_x = candidates
        .iter()
        .fold(0i64, |sum, point| sum + i64::from(point.x()));
    let sum_y = candidates
        .iter()
        .fold(0i64, |sum, point| sum + i64::from(point.y()));
    let count = candidates.len() as i64;
    success_data_test_project_fdm_point(
        layout,
        projection,
        (sum_x / count) as i32,
        (sum_y / count) as i32,
    )
}

fn success_data_test_projected_fdm_control_ellipse_arc_path_data(
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    ellipse: ObjectFdmVectorEllipse,
    commands: &[&ObjectFdmVectorCommandCandidate],
) -> Option<String> {
    let center = ellipse.center();
    let (cx, cy, rx, ry) = success_data_test_projected_fdm_ellipse(layout, projection, ellipse)?;
    let mut rays =
        success_data_test_control_ellipse_angle_rays(center, ellipse.radius_x(), commands)
            .into_iter()
            .filter_map(|endpoint| {
                let (x, y) = success_data_test_project_fdm_point(
                    layout,
                    projection,
                    endpoint.x(),
                    endpoint.y(),
                )?;
                let dx = x - cx;
                let dy = y - cy;
                let distance = (dx * dx + dy * dy).sqrt();
                (distance > 1.0 && dy > 0.0).then_some((dx / distance, dy / distance))
            })
            .collect::<Vec<_>>();
    if rays.len() < 2 {
        return None;
    }
    rays.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));
    let first = *rays.first()?;
    let last = *rays.last()?;
    let mid = {
        let x = first.0 + last.0;
        let y = first.1 + last.1;
        let distance = (x * x + y * y).sqrt();
        if distance > 0.001 && y > 0.0 {
            (x / distance, y / distance)
        } else {
            (0.0, 1.0)
        }
    };
    let start = (cx + first.0 * rx, cy + first.1 * ry);
    let through = (cx + mid.0 * rx, cy + mid.1 * ry);
    let end = (cx + last.0 * rx, cy + last.1 * ry);
    let control = fdm_quadratic_control_point(start, through, end);
    Some(format!(
        "M {:.1} {:.1} Q {:.1} {:.1} {:.1} {:.1}",
        start.0, start.1, control.0, control.1, end.0, end.1
    ))
}

fn success_data_test_control_ellipse_angle_rays(
    center: ObjectFdmVectorPoint,
    radius: i32,
    commands: &[&ObjectFdmVectorCommandCandidate],
) -> Vec<ObjectFdmVectorPoint> {
    let proximity = (radius / 3).max(12) as f32;
    let mut rays = Vec::new();
    for command in commands {
        if command.ellipse().is_some() {
            continue;
        }
        for segment in command.path_points().windows(2) {
            let start = segment[0];
            let end = segment[1];
            if fdm_point_distance(center, start) <= proximity {
                rays.push(end);
            }
            if fdm_point_distance(center, end) <= proximity {
                rays.push(start);
            }
            if fdm_point_segment_distance(center, start, end) <= proximity {
                rays.push(start);
                rays.push(end);
            }
        }
    }
    rays
}

fn fdm_point_distance(a: ObjectFdmVectorPoint, b: ObjectFdmVectorPoint) -> f32 {
    let dx = (a.x() - b.x()) as f32;
    let dy = (a.y() - b.y()) as f32;
    (dx * dx + dy * dy).sqrt()
}

fn fdm_point_distance_squared(a: ObjectFdmVectorPoint, b: ObjectFdmVectorPoint) -> i64 {
    let dx = i64::from(a.x() - b.x());
    let dy = i64::from(a.y() - b.y());
    dx * dx + dy * dy
}

fn fdm_point_segment_distance(
    point: ObjectFdmVectorPoint,
    start: ObjectFdmVectorPoint,
    end: ObjectFdmVectorPoint,
) -> f32 {
    let px = point.x() as f32;
    let py = point.y() as f32;
    let sx = start.x() as f32;
    let sy = start.y() as f32;
    let ex = end.x() as f32;
    let ey = end.y() as f32;
    let dx = ex - sx;
    let dy = ey - sy;
    let length_squared = dx * dx + dy * dy;
    if length_squared <= f32::EPSILON {
        return ((px - sx) * (px - sx) + (py - sy) * (py - sy)).sqrt();
    }
    let t = (((px - sx) * dx + (py - sy) * dy) / length_squared).clamp(0.0, 1.0);
    let x = sx + t * dx;
    let y = sy + t * dy;
    ((px - x) * (px - x) + (py - y) * (py - y)).sqrt()
}

fn push_success_data_test_fdm_text_projection_svg(
    svg: &mut String,
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    source_path: &str,
    candidates: &[ObjectFdmTextCandidate],
    font_family: &str,
) {
    let text_candidates = candidates
        .iter()
        .filter(|candidate| success_data_test_fdm_text_projection_candidate(projection, candidate))
        .collect::<Vec<_>>();
    if text_candidates.is_empty() {
        return;
    }

    svg.push_str(&format!(
        "<g class=\"rjtd-success-data-test-fdm-text-projection\" data-role=\"{}\" data-source-path=\"{}\" data-projection=\"successDataTestFdmTextProjection\" data-text-count=\"{}\" data-reference-backed=\"true\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\">",
        escape_xml(projection.role),
        escape_xml(source_path),
        text_candidates.len()
    ));
    for candidate in text_candidates {
        let Some((x, y, font_size)) =
            success_data_test_projected_fdm_text_bbox(layout, projection, candidate)
        else {
            continue;
        };
        svg.push_str(&format!(
            "<text class=\"rjtd-success-data-test-fdm-text\" data-role=\"{}\" data-text-offset=\"{}\" data-marker-offset=\"{}\" x=\"{x:.1}\" y=\"{y:.1}\" text-anchor=\"middle\" font-family=\"{}\" font-size=\"{font_size:.1}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
            escape_xml(projection.role),
            candidate.text_offset(),
            candidate.marker_offset(),
            escape_xml(font_family),
            escape_xml(&svg_visual_text(candidate.text()))
        ));
    }
    svg.push_str("</g>");
}

fn success_data_test_fdm_text_projection_candidate(
    projection: SuccessDataTestFdmProjection,
    candidate: &ObjectFdmTextCandidate,
) -> bool {
    let Some((left, top, right, bottom)) = candidate.bbox().map(normalize_fdm_bbox) else {
        return false;
    };
    let center_x = left + (right - left) / 2;
    let center_y = top + (bottom - top) / 2;
    center_x >= projection.source_left
        && center_x <= projection.source_right
        && center_y >= projection.source_top
        && center_y <= projection.source_bottom
}

fn success_data_test_projected_fdm_text_bbox(
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    candidate: &ObjectFdmTextCandidate,
) -> Option<(f32, f32, f32)> {
    let bbox = candidate.bbox().map(normalize_fdm_bbox)?;
    let center_x = bbox.0 + (bbox.2 - bbox.0) / 2;
    let center_y = bbox.1 + (bbox.3 - bbox.1) / 2;
    let (_, top_y) = success_data_test_project_fdm_point(layout, projection, bbox.0, bbox.1)?;
    let (_, bottom_y) = success_data_test_project_fdm_point(layout, projection, bbox.2, bbox.3)?;
    let (x, y) = success_data_test_project_fdm_point(layout, projection, center_x, center_y)?;
    let scale_y = layout.height_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_HEIGHT_PX;
    let projected_height = (bottom_y - top_y).abs();
    let (font_size, baseline_factor) = match projection.role {
        "q3-cone-diagram" => (
            (projected_height * 0.80).clamp(
                9.0 * scale_y,
                SUCCESS_DATA_TEST_TOP_TEXT_FONT_SIZE_PX * scale_y,
            ),
            0.34,
        ),
        "q4-angle-diagrams" => (
            (projected_height * SUCCESS_DATA_TEST_Q4_TEXT_HEIGHT_FACTOR)
                .clamp(8.0 * scale_y, 10.8 * scale_y),
            SUCCESS_DATA_TEST_Q4_TEXT_BASELINE_FACTOR,
        ),
        _ => (
            (projected_height * 0.52).clamp(6.2 * scale_y, 9.0 * scale_y),
            0.34,
        ),
    };
    Some((x, y + font_size * baseline_factor, font_size))
}

fn success_data_test_fdm_projection_command(
    projection: SuccessDataTestFdmProjection,
    command: &ObjectFdmVectorCommandCandidate,
) -> bool {
    let Some(bbox) = fdm_vector_command_source_bbox(command).map(normalize_fdm_bbox) else {
        return false;
    };
    let center_x = bbox.0 + (bbox.2 - bbox.0) / 2;
    let center_y = bbox.1 + (bbox.3 - bbox.1) / 2;
    center_x >= projection.source_left
        && center_x <= projection.source_right
        && center_y >= projection.source_top
        && center_y <= projection.source_bottom
}

fn success_data_test_cone_vector_command(
    projection: SuccessDataTestFdmProjection,
    command: &ObjectFdmVectorCommandCandidate,
) -> bool {
    let Some(bbox) = success_data_test_cone_selection_bbox(command).map(normalize_fdm_bbox) else {
        return false;
    };
    let margin = success_data_test_projection_margin_units(projection);
    bbox.0 >= projection.source_left - margin
        && bbox.2 <= projection.source_right + margin
        && bbox.1 >= projection.source_top - margin
        && bbox.3 <= projection.source_bottom + margin
}

fn success_data_test_projection_margin_units(projection: SuccessDataTestFdmProjection) -> i32 {
    let span_x = projection
        .source_right
        .saturating_sub(projection.source_left)
        .abs();
    let span_y = projection
        .source_bottom
        .saturating_sub(projection.source_top)
        .abs();
    span_x.max(span_y).max(128) / 128
}

fn success_data_test_cone_selection_bbox(
    command: &ObjectFdmVectorCommandCandidate,
) -> Option<ObjectFdmIndexBbox> {
    if let Some(ellipse) = command.ellipse() {
        return Some(fdm_vector_ellipse_bbox(ellipse));
    }
    fdm_vector_path_points_bbox(command.path_points())
        .or_else(|| fdm_vector_command_source_bbox(command))
}

fn success_data_test_cone_command_is_dashed(command: &ObjectFdmVectorCommandCandidate) -> bool {
    fdm_vector_marker_is_line(command.marker())
        || (fdm_vector_marker_is_bezier_curve(command.marker()) && command.style_word() != 0)
}

fn success_data_test_projected_fdm_path_data(
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    command: &ObjectFdmVectorCommandCandidate,
) -> Option<String> {
    let mut points = Vec::with_capacity(command.path_points().len());
    for point in command.path_points() {
        points.push(success_data_test_project_fdm_point(
            layout,
            projection,
            point.x(),
            point.y(),
        )?);
    }
    if points.len() < 2 {
        return None;
    }

    let mut path_data = format!("M {:.1} {:.1}", points[0].0, points[0].1);
    if !command.curve_segments().is_empty() {
        for (index, segment) in command.curve_segments().iter().enumerate() {
            if index + 1 >= command.path_points().len() {
                break;
            }
            let control_1 = segment.control_1();
            let control_2 = segment.control_2();
            let end = command.path_points()[index + 1];
            let (control_1_x, control_1_y) = success_data_test_project_fdm_point(
                layout,
                projection,
                control_1.x(),
                control_1.y(),
            )?;
            let (control_2_x, control_2_y) = success_data_test_project_fdm_point(
                layout,
                projection,
                control_2.x(),
                control_2.y(),
            )?;
            let (end_x, end_y) =
                success_data_test_project_fdm_point(layout, projection, end.x(), end.y())?;
            path_data.push_str(&format!(
                " C {control_1_x:.1} {control_1_y:.1} {control_2_x:.1} {control_2_y:.1} {end_x:.1} {end_y:.1}"
            ));
        }
    } else if fdm_vector_marker_is_bezier_curve(command.marker()) && points.len() >= 3 {
        let mut index = 1usize;
        while index + 1 < points.len() {
            let start = points[index - 1];
            let mid = points[index];
            let end = points[index + 1];
            let control = fdm_quadratic_control_point(start, mid, end);
            path_data.push_str(&format!(
                " Q {:.1} {:.1} {:.1} {:.1}",
                control.0, control.1, end.0, end.1
            ));
            index += 2;
        }
        while index < points.len() {
            let point = points[index];
            path_data.push_str(&format!(" L {:.1} {:.1}", point.0, point.1));
            index += 1;
        }
    } else {
        for point in points.iter().skip(1) {
            path_data.push_str(&format!(" L {:.1} {:.1}", point.0, point.1));
        }
    }

    if fdm_vector_path_is_closed(command.path_points()) {
        path_data.push_str(" Z");
    }
    Some(path_data)
}

fn success_data_test_projected_fdm_ellipse(
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    ellipse: ObjectFdmVectorEllipse,
) -> Option<(f32, f32, f32, f32)> {
    let center = ellipse.center();
    let (cx, cy) = success_data_test_project_fdm_point(layout, projection, center.x(), center.y())?;
    let span_x = (projection.source_right - projection.source_left) as f32;
    let span_y = (projection.source_bottom - projection.source_top) as f32;
    if span_x <= 0.0 || span_y <= 0.0 {
        return None;
    }
    let scale_x = layout.width_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_WIDTH_PX;
    let scale_y = layout.height_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_HEIGHT_PX;
    Some((
        cx,
        cy,
        ellipse.radius_x() as f32 / span_x * projection.target_width_px * scale_x,
        ellipse.radius_y() as f32 / span_y * projection.target_height_px * scale_y,
    ))
}

fn success_data_test_project_fdm_point(
    layout: PageLayout,
    projection: SuccessDataTestFdmProjection,
    x: i32,
    y: i32,
) -> Option<(f32, f32)> {
    let span_x = (projection.source_right - projection.source_left) as f32;
    let span_y = (projection.source_bottom - projection.source_top) as f32;
    if span_x <= 0.0 || span_y <= 0.0 {
        return None;
    }
    let scale_x = layout.width_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_WIDTH_PX;
    let scale_y = layout.height_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_HEIGHT_PX;
    Some((
        (projection.target_x_px
            + (x - projection.source_left) as f32 / span_x * projection.target_width_px)
            * scale_x,
        (projection.target_y_px
            + (y - projection.source_top) as f32 / span_y * projection.target_height_px)
            * scale_y,
    ))
}

fn push_page_decoration_svg(
    svg: &mut String,
    layout: PageLayout,
    _writing_mode: WritingMode,
    decoration: &PageDecoration,
    font_family: &str,
) {
    let x = page_decoration_x(layout, decoration.side);
    let header_y = layout.margin_px() * 0.55;
    let page_number_y = layout.height_px() - (layout.margin_px() * 0.45);
    let text_anchor = decoration.side.text_anchor();
    svg.push_str(&format!(
        "<text class=\"rjtd-running-header\" data-source=\"{}\" data-projection-kind=\"layoutStyleAutoTextProjection\" data-decoded=\"false\" data-side=\"{}\" data-side-policy=\"{}\" data-side-policy-decoded=\"{}\" data-facing-pages-candidate=\"{}\" x=\"{x:.1}\" y=\"{header_y:.1}\" text-anchor=\"{text_anchor}\" font-family=\"{font_family}\" font-size=\"{:.1}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
        escape_xml(decoration.source),
        decoration.side.as_str(),
        escape_xml(decoration.side_policy),
        decoration.side_policy_decoded,
        decoration.facing_pages_candidate,
        APP_PAGE_DECORATION_FONT_SIZE_PX,
        escape_xml(&svg_visual_text(&decoration.header_text))
    ));

    svg.push_str(&format!(
        "<text class=\"rjtd-page-number\" data-source=\"{}\" data-projection-kind=\"layoutStyleAutoTextProjection\" data-decoded=\"false\" data-side=\"{}\" data-side-policy=\"{}\" data-side-policy-decoded=\"{}\" data-facing-pages-candidate=\"{}\" x=\"{x:.1}\" y=\"{page_number_y:.1}\" text-anchor=\"{text_anchor}\" font-family=\"{font_family}\" font-size=\"{:.1}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\">{}</text>",
        escape_xml(decoration.source),
        decoration.side.as_str(),
        escape_xml(decoration.side_policy),
        decoration.side_policy_decoded,
        decoration.facing_pages_candidate,
        APP_PAGE_DECORATION_FONT_SIZE_PX,
        decoration.page_number
    ));
}

fn page_decoration_x(layout: PageLayout, side: PageDecorationSide) -> f32 {
    match side {
        PageDecorationSide::Left => layout.margin_px(),
        PageDecorationSide::Right => layout.width_px() - layout.margin_px(),
    }
}

#[allow(clippy::too_many_arguments)]
fn push_svg_text_run(
    svg: &mut String,
    class_name: &str,
    x: f32,
    y: f32,
    font_family: &str,
    font_size: f32,
    fill: &str,
    text: &str,
    writing_mode: Option<&str>,
) {
    let visual_text = escape_xml(&svg_visual_text(text));
    let writing_mode_attr = writing_mode
        .map(|mode| format!(" writing-mode=\"{mode}\""))
        .unwrap_or_default();
    svg.push_str(&format!(
        "<text class=\"{class_name}\" x=\"{x:.1}\" y=\"{y:.1}\" font-family=\"{font_family}\" font-size=\"{font_size:.1}\" fill=\"{fill}\" letter-spacing=\"0\" xml:space=\"preserve\"{writing_mode_attr}>{visual_text}</text>"
    ));
}

fn push_svg_ruby_annotation(
    svg: &mut String,
    x: f32,
    y: f32,
    font_family: &str,
    annotation: &str,
    vertical: bool,
) {
    let writing_mode_attr = if vertical {
        " writing-mode=\"vertical-rl\""
    } else {
        " text-anchor=\"middle\""
    };
    svg.push_str(&format!(
        "<text class=\"rjtd-ruby\" x=\"{x:.1}\" y=\"{y:.1}\" font-family=\"{font_family}\" font-size=\"{:.1}\" fill=\"#111111\" letter-spacing=\"0\" xml:space=\"preserve\"{writing_mode_attr}>{}</text>",
        APP_FONT_SIZE_PX * 0.55,
        escape_xml(&svg_visual_text(annotation))
    ));
}

fn svg_visual_text(text: &str) -> String {
    text.chars()
        .flat_map(|character| match character {
            '\t' => "\u{3000}\u{3000}".chars().collect::<Vec<_>>(),
            _ => vec![character],
        })
        .collect()
}

fn is_centered_ginga_title_page(page_number: usize, line: &PageTextLine) -> bool {
    page_number == 1 && line.text().contains("銀河鉄道の夜") && line.text().contains("宮沢")
}

fn push_image_payload_diagnostic_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
) {
    if page_number != 1 {
        return;
    }

    for (overlay_index, diagnostic) in image_payload_diagnostics(document)
        .into_iter()
        .take(APP_IMAGE_DIAGNOSTIC_MAX_OVERLAYS)
        .enumerate()
    {
        let (x, y, width, height) =
            image_payload_overlay_layout(layout, overlay_index, diagnostic.span);
        let Some(data_uri) = image_payload_svg_data_uri(diagnostic.span) else {
            continue;
        };
        svg.push_str(&format!(
            "<g class=\"rjtd-image-payload-diagnostic\" data-source-path=\"{}\" data-object-candidate-index=\"{}\" data-payload-index=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"true\" data-mime=\"{}\">",
            escape_xml(diagnostic.candidate.path()),
            diagnostic.candidate_index,
            diagnostic.payload_index,
            escape_xml(diagnostic.span.mime())
        ));
        svg.push_str(&format!(
            "<rect x=\"{:.1}\" y=\"{:.1}\" width=\"{:.1}\" height=\"{:.1}\" fill=\"#f8fbff\" stroke=\"#6984a6\" stroke-width=\"0.8\" stroke-dasharray=\"3 2\"/>",
            x - 2.0,
            y - 2.0,
            width + 4.0,
            height + 4.0
        ));
        svg.push_str(&format!(
            "<image x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{height:.1}\" preserveAspectRatio=\"xMidYMid meet\" href=\"{data_uri}\" xlink:href=\"{data_uri}\"/>"
        ));
        svg.push_str("</g>");
    }
}

fn push_fdm_frame_diagnostic_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
) {
    if page_number != 1 {
        return;
    }

    let diagnostics = fdm_frame_diagnostics(document);
    if diagnostics.is_empty() {
        return;
    }

    svg.push_str("<g class=\"rjtd-fdm-frame-diagnostics\" data-source=\"fdmIndex+frame\" data-projection=\"fdmFrameDiagnosticProjection\" data-reference-backed=\"true\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"false\">");
    for diagnostic in diagnostics {
        let Some((x, y, width, height)) = fdm_frame_diagnostic_bbox(layout, diagnostic) else {
            continue;
        };
        svg.push_str(&format!(
            "<g class=\"rjtd-fdm-frame-diagnostic\" data-source-path=\"{}\" data-object-candidate-index=\"{}\" data-row-index=\"{}\" data-frame-object-id=\"{}\" data-frame-type=\"0x{:04x}\" data-projection-kind=\"fdmFrameDiagnosticProjection\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"false\">",
            escape_xml(diagnostic.candidate.path()),
            diagnostic.candidate_index,
            diagnostic.entry.row_index(),
            diagnostic.frame_record.object_id(),
            diagnostic.frame_record.object_type()
        ));
        svg.push_str(&format!(
            "<rect x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{height:.1}\" fill=\"#eaf5ff\" fill-opacity=\"0.18\" stroke=\"#0a66b7\" stroke-width=\"1.2\" stroke-dasharray=\"5 3\"/>"
        ));
        svg.push_str(&format!(
            "<text x=\"{:.1}\" y=\"{:.1}\" font-family=\"Hiragino Sans, Hiragino Kaku Gothic ProN, Yu Gothic, Meiryo, sans-serif\" font-size=\"9.0\" fill=\"#0a66b7\" letter-spacing=\"0\">FDM row {}</text>",
            x + 3.0,
            (y - 4.0).max(10.0),
            diagnostic.entry.row_index()
        ));
        svg.push_str("</g>");
    }
    svg.push_str("</g>");
}

fn push_fdm_command_diagnostic_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
) {
    if page_number != 1 {
        return;
    }

    let diagnostics = fdm_command_diagnostics(document);
    let Some(extent) = fdm_command_projection_extent(&diagnostics) else {
        return;
    };

    svg.push_str("<g class=\"rjtd-fdm-command-diagnostics\" data-source=\"fdmVectorCommand\" data-projection=\"fdmCommandBBoxReferenceProjection\" data-reference-backed=\"true\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"false\">");
    for diagnostic in diagnostics {
        let Some((x, y, width, height)) = fdm_command_diagnostic_bbox(layout, diagnostic, extent)
        else {
            continue;
        };
        let stroke = if diagnostic.entry.row_index() == 23 || diagnostic.entry.row_index() == 33 {
            "#d9432f"
        } else {
            "#4d95ff"
        };
        let opacity = if diagnostic.entry.row_index() == 23 || diagnostic.entry.row_index() == 33 {
            "0.82"
        } else {
            "0.44"
        };
        svg.push_str(&format!(
            "<rect class=\"rjtd-fdm-command-diagnostic\" data-source-path=\"{}\" data-row-index=\"{}\" data-command-index=\"{}\" data-marker-hex=\"{}\" data-projection-kind=\"fdmCommandBBoxReferenceProjection\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-placement-proven=\"false\" data-renderable=\"false\" x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{height:.1}\" fill=\"none\" stroke=\"{stroke}\" stroke-width=\"0.65\" stroke-opacity=\"{opacity}\"/>",
            escape_xml(diagnostic.candidate.path()),
            diagnostic.entry.row_index(),
            diagnostic.command.command_index(),
            hex_bytes(diagnostic.command.marker())
        ));
    }
    svg.push_str("</g>");
}

fn push_fdm_vector_primitive_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    page_number: usize,
) -> bool {
    if page_number != 1 {
        return false;
    }

    let command_diagnostics = fdm_command_diagnostics(document);
    let Some(extent) = fdm_command_projection_extent(&command_diagnostics) else {
        return false;
    };
    let diagnostics = fdm_vector_primitive_diagnostics(document);
    if diagnostics.is_empty() {
        return false;
    }

    let group_start = svg.len();
    let mut rendered = false;
    let mut counter_overlays = String::new();
    svg.push_str("<g class=\"rjtd-fdm-vector-primitives\" data-source=\"fdmVectorCommandPrimitive\" data-projection=\"fdmVectorPrimitiveReferenceProjection\" data-reference-backed=\"true\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\" data-renderable=\"true\">");
    for diagnostic in diagnostics.iter().copied() {
        let Some((path_x, path_y, path_width, path_height)) =
            fdm_path_diagnostic_bbox(layout, diagnostic, extent)
        else {
            continue;
        };

        let path_closed = fdm_vector_primitive_is_closed(diagnostic.command);
        let fill = fdm_vector_render_fill_color(diagnostic, &diagnostics);
        let gradient = fdm_vector_linear_gradient_colors(diagnostic.command);
        let stroke = fdm_vector_render_stroke_color(diagnostic, &diagnostics);
        let data_fill = diagnostic
            .command
            .fill_color()
            .and_then(fdm_vector_css_color)
            .unwrap_or_else(|| "none".to_string());
        let data_stroke = diagnostic
            .command
            .stroke_color()
            .and_then(fdm_vector_css_color)
            .unwrap_or_else(|| "none".to_string());
        let stroke_width = fdm_vector_stroke_width(diagnostic.command);
        let primitive_kind = fdm_vector_primitive_kind(diagnostic.command);
        let page_coverage_ratio =
            projected_bbox_page_coverage_ratio(layout, path_width, path_height);
        let viewport_coverage_ratio =
            projected_bbox_viewport_coverage_ratio(layout, path_width, path_height);

        if let Some(ellipse) = diagnostic.command.ellipse() {
            let Some((cx, cy, rx, ry)) = fdm_projected_ellipse(layout, extent, ellipse) else {
                continue;
            };
            let ellipse_color = ellipse
                .color()
                .and_then(fdm_vector_primitive_css_color)
                .unwrap_or_else(|| "#111111".to_string());
            let fill = if fdm_vector_ellipse_should_fill(ellipse) {
                ellipse_color.as_str()
            } else {
                "none"
            };
            let stroke = if fdm_vector_ellipse_should_fill(ellipse) {
                "none"
            } else {
                ellipse_color.as_str()
            };
            svg.push_str(&format!(
                "<ellipse class=\"rjtd-fdm-vector-primitive\" data-source-path=\"{}\" data-row-index=\"{}\" data-command-index=\"{}\" data-marker-hex=\"{}\" data-primitive-kind=\"{}\" data-style-word=\"0x{:04x}\" data-fill-color=\"{}\" data-stroke-color=\"{}\" data-stroke-width=\"{:.3}\" data-path-closed=\"{}\" data-point-count=\"{}\" data-page-coverage-ratio=\"{page_coverage_ratio:.6}\" data-viewport-coverage-ratio=\"{viewport_coverage_ratio:.6}\" data-page-fill-candidate=\"false\" data-projection-kind=\"fdmVectorPrimitiveReferenceProjection\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\" data-renderable=\"true\" cx=\"{cx:.1}\" cy=\"{cy:.1}\" rx=\"{rx:.1}\" ry=\"{ry:.1}\" fill=\"{}\" stroke=\"{}\" stroke-width=\"{:.3}\" stroke-opacity=\"0.92\"/>",
                escape_xml(diagnostic.candidate.path()),
                diagnostic.entry.row_index(),
                diagnostic.command.command_index(),
                hex_bytes(diagnostic.command.marker()),
                primitive_kind,
                diagnostic.command.style_word(),
                data_fill,
                data_stroke,
                stroke_width,
                path_closed,
                diagnostic.command.path_points().len(),
                fill,
                stroke,
                stroke_width
            ));
            rendered = true;
            continue;
        }

        let Some(path_data) = fdm_projected_path_data(layout, extent, diagnostic.command) else {
            continue;
        };
        let fill_paint = if let Some((gradient_from, gradient_to)) = gradient.as_ref() {
            let gradient_id = format!(
                "rjtd-fdm-gradient-{}-{}",
                diagnostic.entry.row_index(),
                diagnostic.command.command_index()
            );
            svg.push_str(&format!(
                "<defs><linearGradient id=\"{gradient_id}\" gradientUnits=\"userSpaceOnUse\" x1=\"{:.1}\" y1=\"{:.1}\" x2=\"{:.1}\" y2=\"{:.1}\"><stop offset=\"0%\" stop-color=\"{gradient_from}\"/><stop offset=\"100%\" stop-color=\"{gradient_to}\"/></linearGradient></defs>",
                path_x,
                path_y + path_height,
                path_x + path_width,
                path_y
            ));
            format!("url(#{gradient_id})")
        } else {
            fill.clone()
        };
        svg.push_str(&format!(
            "<path class=\"rjtd-fdm-vector-primitive\" data-source-path=\"{}\" data-row-index=\"{}\" data-command-index=\"{}\" data-marker-hex=\"{}\" data-primitive-kind=\"{}\" data-style-word=\"0x{:04x}\" data-fill-color=\"{}\" data-render-fill-kind=\"{}\" data-render-fill-color=\"{}\" data-stroke-color=\"{}\" data-render-stroke-color=\"{}\" data-stroke-width=\"{:.3}\" data-path-closed=\"{}\" data-point-count=\"{}\" data-page-coverage-ratio=\"{page_coverage_ratio:.6}\" data-viewport-coverage-ratio=\"{viewport_coverage_ratio:.6}\" data-page-fill-candidate=\"false\" data-projection-kind=\"fdmVectorPrimitiveReferenceProjection\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\" data-renderable=\"true\" d=\"{}\" fill=\"{}\" stroke=\"{}\" stroke-width=\"{:.3}\" stroke-opacity=\"0.92\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>",
            escape_xml(diagnostic.candidate.path()),
            diagnostic.entry.row_index(),
            diagnostic.command.command_index(),
            hex_bytes(diagnostic.command.marker()),
            primitive_kind,
            diagnostic.command.style_word(),
            data_fill,
            if gradient.is_some() {
                "linearGradient"
            } else if fill == "none" {
                "none"
            } else {
                "solid"
            },
            fill,
            data_stroke,
            stroke,
            stroke_width,
            path_closed,
            diagnostic.command.path_points().len(),
            path_data,
            fill_paint,
            stroke,
            stroke_width
        ));
        if fdm_vector_filled_path_is_counter_overlay(diagnostic, &diagnostics) {
            counter_overlays.push_str(&format!(
                "<path class=\"rjtd-fdm-vector-counter-overlay\" data-source-path=\"{}\" data-row-index=\"{}\" data-command-index=\"{}\" data-marker-hex=\"{}\" data-render-counter-overlay=\"true\" data-render-fill-color=\"{}\" data-projection-kind=\"fdmVectorPrimitiveReferenceProjection\" data-decoded=\"false\" data-geometry-decoded=\"true\" data-placement-proven=\"false\" data-renderable=\"true\" d=\"{}\" fill=\"{}\" stroke=\"none\"/>",
                escape_xml(diagnostic.candidate.path()),
                diagnostic.entry.row_index(),
                diagnostic.command.command_index(),
                hex_bytes(diagnostic.command.marker()),
                fill,
                path_data,
                fill
            ));
        }
        rendered = true;
    }
    svg.push_str(&counter_overlays);
    svg.push_str("</g>");
    if !rendered {
        svg.truncate(group_start);
    }
    rendered
}

fn push_table_grid_candidate_svg(
    svg: &mut String,
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    page_number: usize,
) {
    if page_number != 1 {
        return;
    }

    let form_projection_present =
        observed_form_text_projection(document, layout, page_number).is_some();
    for candidate in document.table_candidates() {
        let Some(grid) = candidate.column_segment_grid_candidate() else {
            continue;
        };
        let reference_layout =
            reference_table_grid_overlay_layout(layout, document, candidate, grid.column_count());
        let source_layout = source_derived_table_grid_overlay_layout(
            layout,
            document,
            lines,
            0,
            candidate,
            grid.column_count(),
        );
        let Some(render_layout) = reference_layout
            .as_ref()
            .map(TableGridRenderLayout::from_reference)
            .or_else(|| {
                source_layout
                    .as_ref()
                    .filter(|layout| {
                        !form_projection_present
                            && table_grid_source_derived_layout_is_renderable(layout)
                    })
                    .map(TableGridRenderLayout::from_source_derived)
            })
        else {
            continue;
        };
        let x = render_layout.x;
        let y = render_layout.y;
        let width = render_layout.width;
        let row_height = render_layout.row_height;
        let render_column_count = render_layout.column_count;
        let projection_kind = if render_layout.reference_backed {
            table_grid_projection_kind(true)
        } else {
            "sourceDerivedDiagnosticProjection"
        };
        let source_anchor_count = table_candidate_source_anchor_count(candidate);
        let fallback_anchor_count =
            table_grid_fallback_text_anchor_count(document, lines, candidate);
        let source_layout_evidence_present = table_grid_source_layout_evidence_present(document);
        let decoded_source_placement_evidence_present =
            table_grid_decoded_source_placement_evidence_present(document, candidate);
        let render_promotion_blocked_reason = if render_layout.reference_backed {
            if decoded_source_placement_evidence_present {
                "none"
            } else {
                "source-layout-position-evidence-missing"
            }
        } else {
            source_layout
                .as_ref()
                .map(|layout| layout.render_promotion_blocked_reason)
                .unwrap_or(render_layout.render_promotion_blocked_reason)
        };
        let placement_derived_from_source = !render_layout.reference_backed;
        svg.push_str(&format!(
            "<g class=\"rjtd-column-grid-candidate\" data-table-candidate-index=\"{}\" data-projection-kind=\"{}\" data-reference-backed=\"{}\" data-source-anchor-evidence=\"true\" data-source-anchor-basis=\"{}\" data-source-anchor-cell-count=\"{}\" data-geometry-derivation-evidence=\"true\" data-source-derived-layout-candidate=\"{}\" data-source-derived-layout-reference-backed=\"false\" data-column-width-basis=\"{}\" data-fallback-text-anchor-count=\"{}\" data-source-layout-evidence-present=\"{}\" data-decoded-source-placement-evidence=\"{}\" data-render-promotion-blocked-reason=\"{}\" data-placement-derived-from-source=\"{}\" data-decoded=\"false\" data-geometry-decoded=\"false\" data-row-count=\"{}\" data-col-count-candidate=\"{}\">",
            candidate.index(),
            projection_kind,
            render_layout.reference_backed,
            candidate.basis().as_str(),
            source_anchor_count,
            source_layout.is_some(),
            render_layout.column_width_basis,
            fallback_anchor_count,
            source_layout_evidence_present,
            decoded_source_placement_evidence_present,
            render_promotion_blocked_reason,
            placement_derived_from_source,
            grid.row_count(),
            render_column_count
        ));
        let table_height = row_height * grid.row_count() as f32;
        svg.push_str(&format!(
            "<rect x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{table_height:.1}\" rx=\"{:.1}\" ry=\"{:.1}\" fill=\"#ffffff\" stroke=\"#222222\" stroke-width=\"{:.1}\"/>",
            render_layout.corner_radius,
            render_layout.corner_radius,
            render_layout.stroke_width
        ));
        if render_layout.header_fill {
            svg.push_str(&format!(
                "<rect x=\"{x:.1}\" y=\"{y:.1}\" width=\"{width:.1}\" height=\"{row_height:.1}\" fill=\"#f4f4f4\" stroke=\"none\"/>"
            ));
        }
        for row_index in 0..grid.row_count() {
            let row_y = y + row_index as f32 * row_height;
            for column_index in 0..render_column_count {
                let column_x = render_layout.column_x_at(column_index);
                let column_width = render_layout.column_width_at(column_index);
                svg.push_str(&format!(
                    "<rect x=\"{column_x:.1}\" y=\"{row_y:.1}\" width=\"{column_width:.1}\" height=\"{row_height:.1}\" fill=\"none\" stroke=\"#222222\" stroke-width=\"{:.1}\"/>",
                    render_layout.cell_stroke_width
                ));
            }
        }

        for (row_index, interval) in candidate.intervals().iter().enumerate() {
            let row_y = y + row_index as f32 * row_height;
            for (column_index, segment) in interval.column_segments().iter().enumerate() {
                let column_index =
                    table_grid_segment_column_index(document, candidate, interval, column_index);
                if column_index >= render_column_count {
                    break;
                }
                let column_x = render_layout.column_x_at(column_index);
                let column_width = render_layout.column_width_at(column_index);
                let text_x = if render_layout.cell_text_centered {
                    column_x + (column_width * 0.5)
                } else {
                    column_x + 3.0
                };
                let text_y = if render_layout.cell_text_centered {
                    row_y + (row_height * 0.72)
                } else {
                    row_y + (row_height * 0.64)
                };
                let source_attrs = table_grid_segment_source_svg_attrs(candidate, segment);
                svg.push_str(&format!(
                    "<text x=\"{text_x:.1}\" y=\"{text_y:.1}\" font-family=\"Hiragino Sans, Hiragino Kaku Gothic ProN, Yu Gothic, Meiryo, Noto Sans CJK JP, sans-serif\" font-size=\"{:.1}\" font-weight=\"{}\" fill=\"#333333\" letter-spacing=\"0\"{}{}>{}</text>",
                    render_layout.font_size,
                    if render_layout.header_fill && row_index == 0 {
                        "700"
                    } else {
                        "500"
                    },
                    if render_layout.cell_text_centered {
                        " text-anchor=\"middle\""
                    } else {
                        ""
                    },
                    source_attrs,
                    escape_xml(&preview_svg_cell_text(layout, segment.text(), column_width))
                ));
            }
        }
        svg.push_str("</g>");
    }
}

fn table_grid_overlay_layout(
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    overlay_index: usize,
    candidate: &TableCandidate,
    column_count: usize,
) -> (f32, f32, f32, f32, f32) {
    if let Some(layout) =
        tsaiten_table_grid_overlay_layout(layout, document, candidate, column_count)
    {
        return layout;
    }
    let width = layout.body_width_px();
    let row_height = 18.0;
    let column_width = width / column_count.max(1) as f32;
    if let Some(anchor_line) = table_candidate_anchor_line_index(document, lines, candidate) {
        let y = layout.margin_px() + APP_FONT_SIZE_PX + (anchor_line as f32 * APP_LINE_HEIGHT_PX)
            - 4.0
            + overlay_index as f32 * 4.0;
        return (layout.margin_px(), y, width, row_height, column_width);
    }
    let text_bottom =
        layout.margin_px() + APP_FONT_SIZE_PX + (lines.len() as f32 * APP_LINE_HEIGHT_PX) + 18.0;
    let overlay_top = (layout.height_px() - layout.margin_px() - 210.0).max(layout.margin_px());
    let y = text_bottom.min(overlay_top) + overlay_index as f32 * 96.0;
    (layout.margin_px(), y, width, row_height, column_width)
}

fn table_grid_fallback_overlay_layout(
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    overlay_index: usize,
    candidate: &TableCandidate,
    column_count: usize,
) -> (f32, f32, f32, f32, f32, Option<usize>) {
    let width = layout.body_width_px();
    let row_height = 18.0;
    let column_width = width / column_count.max(1) as f32;
    if let Some(anchor_line) = table_candidate_anchor_line_index(document, lines, candidate) {
        let y = layout.margin_px() + APP_FONT_SIZE_PX + (anchor_line as f32 * APP_LINE_HEIGHT_PX)
            - 4.0
            + overlay_index as f32 * 4.0;
        return (
            layout.margin_px(),
            y,
            width,
            row_height,
            column_width,
            Some(anchor_line),
        );
    }
    let text_bottom =
        layout.margin_px() + APP_FONT_SIZE_PX + (lines.len() as f32 * APP_LINE_HEIGHT_PX) + 18.0;
    let overlay_top = (layout.height_px() - layout.margin_px() - 210.0).max(layout.margin_px());
    let y = text_bottom.min(overlay_top) + overlay_index as f32 * 96.0;
    (layout.margin_px(), y, width, row_height, column_width, None)
}

#[derive(Debug, Clone)]
struct TableGridSourceDerivedLayout {
    x: f32,
    y: f32,
    width: f32,
    height: f32,
    row_height: f32,
    column_width: f32,
    column_widths: Vec<f32>,
    column_width_basis: &'static str,
    column_count: usize,
    row_count: usize,
    x_unit_range_basis: &'static str,
    x_unit_start: u16,
    x_unit_end: u16,
    row_height_basis: &'static str,
    page_origin_authority: &'static str,
    anchor_line_index: Option<usize>,
    line_mark_page_origin: Option<TableGridLineMarkPageOriginCandidate>,
    raw_header_count: usize,
    matched_cell_header_count: usize,
    min_offset_units: Option<u16>,
    max_extent_units: Option<u16>,
    matched_cell_span_units: Vec<u16>,
    matched_cell_gap_units: Vec<u16>,
    homogeneous_font_size_units: Option<u16>,
    render_promotion_blocked_reason: &'static str,
}

#[derive(Debug, Clone)]
struct TableGridLineMarkPageOriginCandidate {
    y: f32,
    first_line_mark_record_index: usize,
    last_line_mark_record_index: usize,
    page_mark_entry_index: usize,
    page_index_candidate: Option<usize>,
    page_line_start: usize,
    page_line_end: usize,
    page_mark_u16_fields: Vec<u16>,
    page_width_px: f32,
    page_height_px: f32,
    page_margin_px: f32,
    page_body_width_px: f32,
    line_offset_from_page_start: usize,
    row_height: f32,
}

fn source_derived_table_grid_overlay_layout(
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    overlay_index: usize,
    candidate: &TableCandidate,
    column_count: usize,
) -> Option<TableGridSourceDerivedLayout> {
    if column_count == 0
        || !table_grid_decoded_source_placement_evidence_present(document, candidate)
    {
        return None;
    }

    let rows = table_candidate_document_text_line_header_rows(document, candidate);
    let first_row = rows.first()?;
    let matched_column_count = rows
        .iter()
        .map(|row| row.matched_cell_count)
        .min()
        .unwrap_or(0)
        .min(column_count);
    if matched_column_count == 0 || first_row.headers.len() < matched_column_count {
        return None;
    }

    let raw_header_count = rows
        .iter()
        .map(TableCandidateLineHeaderRow::raw_header_count)
        .sum::<usize>();
    let matched_cell_header_count = rows.iter().map(|row| row.matched_cell_count).sum::<usize>();
    let min_offset_units = rows
        .iter()
        .flat_map(|row| row.headers.iter().map(|header| header.offset_units))
        .min();
    let max_extent_units = rows
        .iter()
        .flat_map(|row| row.headers.iter().map(|header| header.extent_units))
        .max();
    let homogeneous_font_size_units = rows
        .iter()
        .flat_map(|row| row.headers.iter().map(|header| header.font_size_units))
        .try_fold(None, |seen, value| match seen {
            Some(previous) if previous != value => None,
            _ => Some(Some(value)),
        })
        .flatten();
    let first_matched_header = first_row.headers.first()?;
    let last_matched_header = first_row.headers.get(matched_column_count - 1)?;
    let min_offset = min_offset_units?;
    let max_extent = max_extent_units?;
    if max_extent <= min_offset
        || last_matched_header.extent_units <= first_matched_header.offset_units
    {
        return None;
    }

    let matched_headers = first_row
        .headers
        .iter()
        .take(matched_column_count)
        .collect::<Vec<_>>();
    let matched_cell_span_units = matched_headers
        .iter()
        .map(|header| header.extent_units.saturating_sub(header.offset_units))
        .collect::<Vec<_>>();
    if matched_cell_span_units.contains(&0) {
        return None;
    }
    let matched_cell_gap_units = matched_headers
        .windows(2)
        .map(|pair| pair[1].offset_units.saturating_sub(pair[0].extent_units))
        .collect::<Vec<_>>();

    let (fallback_x, fallback_y, fallback_width, fallback_row_height, _, anchor_line_index) =
        table_grid_fallback_overlay_layout(
            layout,
            document,
            lines,
            overlay_index,
            candidate,
            column_count,
        );
    let source_full_span = f32::from(max_extent.saturating_sub(min_offset));
    if source_full_span <= 0.0 {
        return None;
    }
    let strong_line_mark_rows =
        table_grid_line_mark_rows_are_exact_and_contiguous(document, candidate, &rows);
    let (x_unit_start, x_unit_end, x_unit_range_basis) = if strong_line_mark_rows {
        table_grid_unit_bbox_range_for_row(
            first_row,
            matched_column_count,
            TableGridUnitBBoxBasis::MatchedCellsPlusFirstTrailingHeader,
        )
        .map(|(start, end)| (start, end, "matched-cells-plus-first-trailing-header"))
    } else {
        None
    }
    .or_else(|| {
        table_grid_unit_bbox_range_for_row(
            first_row,
            matched_column_count,
            TableGridUnitBBoxBasis::MatchedCells,
        )
        .map(|(start, end)| (start, end, "matched-cells"))
    })?;
    let table_offset_units = x_unit_start.saturating_sub(min_offset);
    let table_span_units = x_unit_end.saturating_sub(x_unit_start);
    if table_span_units == 0 {
        return None;
    }
    let x = fallback_x + fallback_width * f32::from(table_offset_units) / source_full_span;
    let width = fallback_width * f32::from(table_span_units) / source_full_span;
    if width <= 0.0 {
        return None;
    }
    let row_height = homogeneous_font_size_units
        .map(|font_size_units| f32::from(font_size_units) * 1.75)
        .unwrap_or(fallback_row_height)
        .max(fallback_row_height * 0.75);
    let row_height_basis = if homogeneous_font_size_units.is_some() {
        "documentTextLineHeaderFontSizeUnits"
    } else {
        "fallbackRowHeight"
    };
    let line_mark_page_origin =
        table_grid_line_mark_page_origin_candidate(layout, document, candidate, &rows, row_height);
    let (y, page_origin_authority, render_promotion_blocked_reason) =
        if let Some(ref origin) = line_mark_page_origin {
            (
                origin.y,
                "lineMarkPageGrid",
                "horizontal-page-unit-scale-unproven",
            )
        } else if anchor_line_index.is_some() {
            (
                fallback_y,
                "fallbackTextAnchors",
                "page-space-origin-and-row-baseline-unproven",
            )
        } else {
            (
                fallback_y,
                "compatibilityProjection",
                "page-space-origin-and-row-baseline-unproven",
            )
        };
    let column_widths =
        table_grid_line_header_column_widths_px(document, candidate, width, matched_column_count);
    let column_width_basis = if column_widths.is_empty() {
        "equalSourceDerivedColumns"
    } else {
        "documentTextLineHeaderSpanUnits"
    };
    let column_width = width / matched_column_count.max(1) as f32;

    Some(TableGridSourceDerivedLayout {
        x,
        y,
        width,
        height: row_height * rows.len() as f32,
        row_height,
        column_width,
        column_widths,
        column_width_basis,
        column_count: matched_column_count,
        row_count: rows.len(),
        x_unit_range_basis,
        x_unit_start,
        x_unit_end,
        row_height_basis,
        page_origin_authority,
        anchor_line_index,
        line_mark_page_origin,
        raw_header_count,
        matched_cell_header_count,
        min_offset_units: Some(min_offset),
        max_extent_units: Some(max_extent),
        matched_cell_span_units,
        matched_cell_gap_units,
        homogeneous_font_size_units,
        render_promotion_blocked_reason,
    })
}

fn table_grid_source_derived_layout_is_renderable(layout: &TableGridSourceDerivedLayout) -> bool {
    layout.anchor_line_index.is_some() && layout.page_origin_authority == "fallbackTextAnchors"
}

fn table_grid_line_mark_page_origin_candidate(
    layout: PageLayout,
    document: &Document,
    candidate: &TableCandidate,
    rows: &[TableCandidateLineHeaderRow],
    row_height: f32,
) -> Option<TableGridLineMarkPageOriginCandidate> {
    if rows.is_empty() || row_height <= 0.0 {
        return None;
    }
    let matched_record_indexes = table_grid_line_mark_record_indexes_for_rows(document, candidate);
    if matched_record_indexes.len() != rows.len()
        || !matched_record_indexes
            .windows(2)
            .all(|pair| pair[1] == pair[0] + 1)
    {
        return None;
    }

    let page_mark = document.page_marks().first()?;
    let mut page_entries = Vec::new();
    for record_index in &matched_record_indexes {
        let entry = page_mark.entries().iter().find(|entry| {
            let Some(line_start) = entry.line_start().map(|value| value as usize) else {
                return false;
            };
            let Some(line_end) = entry.line_end().map(|value| value as usize) else {
                return false;
            };
            line_start <= *record_index && *record_index <= line_end
        })?;
        page_entries.push(entry);
    }

    let first_entry = page_entries.first().copied()?;
    if !page_entries
        .iter()
        .all(|entry| entry.row_index() == first_entry.row_index())
    {
        return None;
    }
    let page_line_start = first_entry.line_start()? as usize;
    let page_line_end = first_entry.line_end()? as usize;
    let first_line_mark_record_index = *matched_record_indexes.first()?;
    let last_line_mark_record_index = *matched_record_indexes.last()?;
    if first_line_mark_record_index < page_line_start || page_line_end < last_line_mark_record_index
    {
        return None;
    }
    let line_offset_from_page_start = first_line_mark_record_index.saturating_sub(page_line_start);
    let y = layout.margin_px() + line_offset_from_page_start as f32 * row_height;

    Some(TableGridLineMarkPageOriginCandidate {
        y,
        first_line_mark_record_index,
        last_line_mark_record_index,
        page_mark_entry_index: first_entry.row_index(),
        page_index_candidate: first_entry.index().map(|index| index as usize),
        page_line_start,
        page_line_end,
        page_mark_u16_fields: first_entry.u16_fields().to_vec(),
        page_width_px: layout.width_px(),
        page_height_px: layout.height_px(),
        page_margin_px: layout.margin_px(),
        page_body_width_px: layout.body_width_px(),
        line_offset_from_page_start,
        row_height,
    })
}

fn table_grid_line_mark_rows_are_exact_and_contiguous(
    document: &Document,
    candidate: &TableCandidate,
    rows: &[TableCandidateLineHeaderRow],
) -> bool {
    let line_mark_intervals = shanai_lan_line_mark_intervals(document);
    if rows.is_empty() || line_mark_intervals.is_empty() {
        return false;
    }
    let mut matched_record_indexes = Vec::new();
    for row in rows {
        let row_unit_start = table_source_offset_to_units(candidate.basis(), row.source_start);
        let row_unit_end = table_source_offset_to_units(candidate.basis(), row.source_end);
        let Some(interval) = line_mark_intervals.iter().find(|interval| {
            interval.unit_start < row_unit_end && row_unit_start < interval.unit_end
        }) else {
            return false;
        };
        if interval.unit_start != row_unit_start || interval.unit_end != row_unit_end {
            return false;
        }
        matched_record_indexes.push(interval.record_index);
    }
    matched_record_indexes
        .windows(2)
        .all(|pair| pair[1] == pair[0] + 1)
}

#[derive(Debug, Clone)]
struct TableGridReferenceLayout {
    x: f32,
    y: f32,
    width: f32,
    row_height: f32,
    column_width: f32,
    column_widths: Vec<f32>,
    column_width_basis: &'static str,
    column_count: usize,
    header_fill: bool,
    corner_radius: f32,
    stroke_width: f32,
    cell_stroke_width: f32,
    font_size: f32,
    cell_text_centered: bool,
}

#[derive(Debug, Clone)]
struct TableGridRenderLayout {
    x: f32,
    y: f32,
    width: f32,
    row_height: f32,
    column_width: f32,
    column_widths: Vec<f32>,
    column_width_basis: &'static str,
    column_count: usize,
    header_fill: bool,
    corner_radius: f32,
    stroke_width: f32,
    cell_stroke_width: f32,
    font_size: f32,
    cell_text_centered: bool,
    reference_backed: bool,
    render_promotion_blocked_reason: &'static str,
}

impl TableGridRenderLayout {
    fn from_reference(reference: &TableGridReferenceLayout) -> Self {
        Self {
            x: reference.x,
            y: reference.y,
            width: reference.width,
            row_height: reference.row_height,
            column_width: reference.column_width,
            column_widths: reference.column_widths.clone(),
            column_width_basis: reference.column_width_basis,
            column_count: reference.column_count,
            header_fill: reference.header_fill,
            corner_radius: reference.corner_radius,
            stroke_width: reference.stroke_width,
            cell_stroke_width: reference.cell_stroke_width,
            font_size: reference.font_size,
            cell_text_centered: reference.cell_text_centered,
            reference_backed: true,
            render_promotion_blocked_reason: "none",
        }
    }

    fn from_source_derived(source: &TableGridSourceDerivedLayout) -> Self {
        Self {
            x: source.x,
            y: source.y,
            width: source.width,
            row_height: source.row_height,
            column_width: source.column_width,
            column_widths: source.column_widths.clone(),
            column_width_basis: source.column_width_basis,
            column_count: source.column_count,
            header_fill: false,
            corner_radius: 0.0,
            stroke_width: 1.0,
            cell_stroke_width: 0.75,
            font_size: APP_FONT_SIZE_PX,
            cell_text_centered: false,
            reference_backed: false,
            render_promotion_blocked_reason: source.render_promotion_blocked_reason,
        }
    }

    fn column_width_at(&self, column_index: usize) -> f32 {
        table_grid_column_width(self.column_width, &self.column_widths, column_index)
    }

    fn column_x_at(&self, column_index: usize) -> f32 {
        table_grid_column_x(self.x, self.column_width, &self.column_widths, column_index)
    }
}

fn table_grid_column_width(default_column_width: f32, column_widths: &[f32], index: usize) -> f32 {
    column_widths
        .get(index)
        .copied()
        .unwrap_or(default_column_width)
}

fn table_grid_column_x(
    left: f32,
    default_column_width: f32,
    column_widths: &[f32],
    index: usize,
) -> f32 {
    if column_widths.is_empty() {
        left + index as f32 * default_column_width
    } else {
        left + column_widths.iter().take(index).copied().sum::<f32>()
    }
}

fn table_grid_projection_kind(reference_projection: bool) -> &'static str {
    if reference_projection {
        "tableProjection"
    } else {
        "diagnosticProjection"
    }
}

fn table_candidate_source_anchor_count(candidate: &TableCandidate) -> usize {
    candidate
        .intervals()
        .iter()
        .flat_map(TableCandidateInterval::column_segments)
        .filter(|segment| {
            matches!(
                (segment.source_start(), segment.source_end()),
                (Some(start), Some(end)) if start < end
            )
        })
        .count()
}

fn table_grid_fallback_text_anchor_count(
    document: &Document,
    lines: &[PageTextLine],
    candidate: &TableCandidate,
) -> usize {
    lines
        .iter()
        .flat_map(|line| page_text_line_fragments(document, line))
        .filter_map(|fragment| fragment.source_span)
        .filter(|span| table_candidate_overlaps_source_span(candidate, span))
        .count()
}

fn table_grid_source_layout_evidence_present(document: &Document) -> bool {
    !document.text_count_ranges().is_empty()
        || raw_stream_bytes(document, LAYOUT_BOX_PATH).is_some()
        || raw_stream_bytes(document, LAYOUT_BOX_TEXT_PATH).is_some()
        || raw_stream_bytes(document, LAYOUT_BOX_TEXT_POSITION_TABLES_PATH).is_some()
}

fn table_grid_decoded_source_placement_evidence_present(
    document: &Document,
    candidate: &TableCandidate,
) -> bool {
    let required = table_grid_decoded_source_placement_required_cell_count(candidate);
    required > 0 && table_grid_decoded_source_placement_match_count(document, candidate) >= required
}

fn table_grid_decoded_source_placement_required_cell_count(candidate: &TableCandidate) -> usize {
    candidate.cell_count_candidate()
}

fn table_grid_decoded_source_placement_match_count(
    document: &Document,
    candidate: &TableCandidate,
) -> usize {
    table_candidate_document_text_line_header_rows(document, candidate)
        .iter()
        .map(|row| row.matched_cell_count)
        .sum()
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TableCandidateLineHeaderRow {
    row_index: usize,
    source_start: usize,
    source_end: usize,
    expected_cell_count: usize,
    matched_cell_count: usize,
    headers: Vec<ShanaiLanLineHeader>,
}

impl TableCandidateLineHeaderRow {
    fn raw_header_count(&self) -> usize {
        self.headers.len()
    }
}

fn table_candidate_document_text_line_header_rows(
    document: &Document,
    candidate: &TableCandidate,
) -> Vec<TableCandidateLineHeaderRow> {
    if !candidate.is_document_text_control_run_candidate() {
        return Vec::new();
    }
    let Some(bytes) = document_text_raw_stream(document) else {
        return Vec::new();
    };

    candidate
        .intervals()
        .iter()
        .enumerate()
        .map(|(row_index, interval)| {
            let expected_cell_count = interval.column_segments().len();
            let headers =
                table_candidate_line_headers_for_interval(bytes, candidate.basis(), interval);
            let matched_cell_count =
                table_candidate_line_header_matched_cell_count(&headers, expected_cell_count);
            TableCandidateLineHeaderRow {
                row_index,
                source_start: interval.source_start(),
                source_end: interval.source_end(),
                expected_cell_count,
                matched_cell_count,
                headers,
            }
        })
        .collect()
}

fn table_candidate_line_headers_for_interval(
    bytes: &[u8],
    basis: TextCountRangeOverlapBasis,
    interval: &TableCandidateInterval,
) -> Vec<ShanaiLanLineHeader> {
    let Some((mut offset, end)) = table_candidate_interval_byte_range(
        bytes,
        basis,
        interval.source_start(),
        interval.source_end(),
    ) else {
        return Vec::new();
    };
    if offset % 2 != 0 {
        offset += 1;
    }
    let mut headers = Vec::new();
    while offset + 24 <= end {
        if let Some(header) = shanai_lan_line_header_at(bytes, offset) {
            headers.push(header);
            offset = header.end;
        } else {
            offset += 2;
        }
    }
    headers
}

fn table_candidate_interval_byte_range(
    bytes: &[u8],
    basis: TextCountRangeOverlapBasis,
    source_start: usize,
    source_end: usize,
) -> Option<(usize, usize)> {
    if source_start >= source_end {
        return None;
    }
    let (byte_start, byte_end) = match basis {
        TextCountRangeOverlapBasis::Byte => (source_start, source_end),
        TextCountRangeOverlapBasis::Unit => {
            (source_start.checked_mul(2)?, source_end.checked_mul(2)?)
        }
    };
    if byte_start >= bytes.len() || byte_start >= byte_end {
        return None;
    }
    Some((byte_start, byte_end.min(bytes.len())))
}

fn table_candidate_line_header_matched_cell_count(
    headers: &[ShanaiLanLineHeader],
    expected_cell_count: usize,
) -> usize {
    if expected_cell_count == 0 || headers.len() < expected_cell_count {
        return 0;
    }
    let mut previous_offset = None;
    for header in headers {
        if header.extent_units <= header.offset_units || header.font_size_units == 0 {
            return 0;
        }
        if previous_offset.is_some_and(|offset| header.offset_units <= offset) {
            return 0;
        }
        previous_offset = Some(header.offset_units);
    }
    expected_cell_count
}

fn table_line_header_source_offset(basis: TextCountRangeOverlapBasis, byte_offset: usize) -> usize {
    match basis {
        TextCountRangeOverlapBasis::Byte => byte_offset,
        TextCountRangeOverlapBasis::Unit => byte_offset / 2,
    }
}

fn table_grid_segment_source_svg_attrs(
    candidate: &TableCandidate,
    segment: &TableCandidateColumnSegment,
) -> String {
    match (segment.source_start(), segment.source_end()) {
        (Some(start), Some(end)) if start < end => format!(
            " data-source-range-basis=\"{}\" data-source-start=\"{}\" data-source-end=\"{}\"",
            candidate.basis().as_str(),
            start,
            end
        ),
        _ => String::new(),
    }
}

fn reference_table_grid_overlay_layout(
    layout: PageLayout,
    document: &Document,
    candidate: &TableCandidate,
    column_count: usize,
) -> Option<TableGridReferenceLayout> {
    if let Some(layout) = success_data_test_table_grid_overlay_layout(layout, document, candidate) {
        return Some(layout);
    }
    let (x, y, width, row_height, column_width) =
        tsaiten_table_grid_overlay_layout(layout, document, candidate, column_count)?;
    Some(TableGridReferenceLayout {
        x,
        y,
        width,
        row_height,
        column_width,
        column_widths: Vec::new(),
        column_width_basis: "equalReferenceColumns",
        column_count,
        header_fill: true,
        corner_radius: 4.0,
        stroke_width: 1.1,
        cell_stroke_width: 0.75,
        font_size: 10.5,
        cell_text_centered: false,
    })
}

fn success_data_test_table_grid_overlay_layout(
    layout: PageLayout,
    document: &Document,
    candidate: &TableCandidate,
) -> Option<TableGridReferenceLayout> {
    if !document_has_success_data_test_projection_evidence(document)
        || !success_data_test_abc_table_candidate(candidate)
        || !table_grid_decoded_source_placement_evidence_present(document, candidate)
    {
        return None;
    }
    let scale_x = layout.width_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_WIDTH_PX;
    let scale_y = layout.height_px() / SUCCESS_DATA_TEST_REFERENCE_PAGE_HEIGHT_PX;
    let width = SUCCESS_DATA_TEST_ABC_TABLE_WIDTH_PX * scale_x;
    let column_count = candidate
        .column_segment_grid_candidate()
        .map(|grid| grid.column_count())
        .filter(|column_count| *column_count > 0)
        .unwrap_or_else(|| candidate.max_column_segment_count().max(1));
    let column_widths =
        table_grid_line_header_column_widths_px(document, candidate, width, column_count);
    let column_width = width / column_count as f32;
    Some(TableGridReferenceLayout {
        x: SUCCESS_DATA_TEST_ABC_TABLE_X_PX * scale_x,
        y: SUCCESS_DATA_TEST_ABC_TABLE_Y_PX * scale_y,
        width,
        row_height: SUCCESS_DATA_TEST_ABC_TABLE_ROW_HEIGHT_PX * scale_y,
        column_width,
        column_width_basis: if column_widths.is_empty() {
            "equalReferenceColumns"
        } else {
            "documentTextLineHeaderSpanUnits"
        },
        column_widths,
        column_count,
        header_fill: false,
        corner_radius: 0.0,
        stroke_width: 1.35,
        cell_stroke_width: 1.1,
        font_size: 14.0,
        cell_text_centered: true,
    })
}

fn tsaiten_table_grid_overlay_layout(
    layout: PageLayout,
    document: &Document,
    candidate: &TableCandidate,
    column_count: usize,
) -> Option<(f32, f32, f32, f32, f32)> {
    if !document_has_tsaiten_projection_evidence(document) {
        return None;
    }
    let scale_x = layout.width_px() / TSAITEN_REFERENCE_PAGE_WIDTH_PX;
    let scale_y = layout.height_px() / TSAITEN_REFERENCE_PAGE_HEIGHT_PX;
    let (x, y, width, row_height) = if column_count == 3
        && candidate.intervals().len() == 4
        && candidate
            .intervals()
            .first()
            .is_some_and(|interval| interval.text_preview() == "級\t配点\t合格点")
    {
        (174.0, 301.0, 421.0, 32.2)
    } else if column_count == 2
        && candidate.intervals().len() == 3
        && candidate
            .intervals()
            .get(1)
            .is_some_and(|interval| interval.text_preview().contains("誤字・脱字・余字"))
    {
        (174.0, 768.0, 554.0, 37.3)
    } else {
        return None;
    };
    let width = width * scale_x;
    Some((
        x * scale_x,
        y * scale_y,
        width,
        row_height * scale_y,
        width / column_count.max(1) as f32,
    ))
}

fn table_grid_line_header_column_widths_px(
    document: &Document,
    candidate: &TableCandidate,
    table_width: f32,
    column_count: usize,
) -> Vec<f32> {
    if column_count == 0 {
        return Vec::new();
    }
    let rows = table_candidate_document_text_line_header_rows(document, candidate);
    let Some(first_row) = rows.first() else {
        return Vec::new();
    };
    if first_row.matched_cell_count < column_count || first_row.headers.len() < column_count {
        return Vec::new();
    }
    let span_units = first_row
        .headers
        .iter()
        .take(column_count)
        .map(|header| header.extent_units.saturating_sub(header.offset_units))
        .collect::<Vec<_>>();
    if span_units.contains(&0) {
        return Vec::new();
    }
    let total_units = span_units.iter().map(|span| f32::from(*span)).sum::<f32>();
    if total_units <= 0.0 {
        return Vec::new();
    }
    span_units
        .into_iter()
        .map(|span| table_width * f32::from(span) / total_units)
        .collect()
}

fn table_grid_segment_column_index(
    _document: &Document,
    _candidate: &TableCandidate,
    _interval: &TableCandidateInterval,
    segment_index: usize,
) -> usize {
    segment_index
}

fn table_candidate_anchor_line_index(
    document: &Document,
    lines: &[PageTextLine],
    candidate: &TableCandidate,
) -> Option<usize> {
    lines.iter().enumerate().find_map(|(line_index, line)| {
        page_text_line_fragments(document, line)
            .into_iter()
            .filter_map(|fragment| fragment.source_span)
            .any(|span| table_candidate_overlaps_source_span(candidate, &span))
            .then_some(line_index)
    })
}

fn fragment_overlaps_rendered_table_projection(
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    page_number: usize,
    fragment: &PageLayerTextFragment,
) -> bool {
    if page_number != 1 {
        return false;
    }
    let Some(span) = &fragment.source_span else {
        return false;
    };
    document.table_candidates().iter().any(|candidate| {
        table_grid_candidate_is_rendered(layout, document, lines, page_number, candidate)
            && table_candidate_overlaps_source_span(candidate, span)
    })
}

fn table_grid_candidate_is_rendered(
    layout: PageLayout,
    document: &Document,
    lines: &[PageTextLine],
    page_number: usize,
    candidate: &TableCandidate,
) -> bool {
    let Some(grid) = candidate.column_segment_grid_candidate() else {
        return false;
    };
    if reference_table_grid_overlay_layout(layout, document, candidate, grid.column_count())
        .is_some()
    {
        return true;
    }
    if observed_form_text_projection(document, layout, page_number).is_some() {
        return false;
    }
    source_derived_table_grid_overlay_layout(
        layout,
        document,
        lines,
        0,
        candidate,
        grid.column_count(),
    )
    .as_ref()
    .is_some_and(table_grid_source_derived_layout_is_renderable)
}

fn table_candidate_overlaps_source_span(candidate: &TableCandidate, span: &TextSourceSpan) -> bool {
    let (span_start, span_end) = match candidate.basis() {
        TextCountRangeOverlapBasis::Byte => (span.byte_start(), span.byte_end()),
        TextCountRangeOverlapBasis::Unit => (span.unit_start(), span.unit_end()),
    };
    candidate.source_start() < span_end && span_start < candidate.source_end()
}

fn preview_svg_cell_text(layout: PageLayout, text: &str, column_width: f32) -> String {
    let max_chars = ((column_width as f64 / column_width_px(layout)).floor() as usize).max(4);
    let mut preview = text.chars().take(max_chars).collect::<String>();
    if text.chars().count() > max_chars {
        preview.push_str("...");
    }
    preview
}

fn image_payload_overlay_layout(
    layout: PageLayout,
    overlay_index: usize,
    span: &ObjectImagePayloadSpan,
) -> (f32, f32, f32, f32) {
    let dimensions = span.dimensions().unwrap();
    let natural_width = dimensions.width().max(1) as f32;
    let natural_height = dimensions.height().max(1) as f32;
    let scale = (APP_IMAGE_DIAGNOSTIC_THUMB_PX / natural_width)
        .min(APP_IMAGE_DIAGNOSTIC_THUMB_PX / natural_height)
        .min(1.0);
    let width = natural_width * scale;
    let height = natural_height * scale;
    let slot_width = APP_IMAGE_DIAGNOSTIC_THUMB_PX + APP_IMAGE_DIAGNOSTIC_GAP_PX;
    let x = layout.margin_px() + overlay_index as f32 * slot_width;
    let y = layout.height_px() - layout.margin_px() - APP_IMAGE_DIAGNOSTIC_THUMB_PX - 22.0;
    (x, y, width, height)
}

fn fdm_frame_diagnostic_bbox(
    layout: PageLayout,
    diagnostic: FdmFrameDiagnostic<'_>,
) -> Option<(f32, f32, f32, f32)> {
    let scale_x = layout.width_px() / SHANAI_LAN_REFERENCE_PAGE_WIDTH_PX;
    let scale_y = layout.height_px() / SHANAI_LAN_REFERENCE_PAGE_HEIGHT_PX;
    let x = diagnostic.frame_record.x() as f32 / SHANAI_LAN_FDM_FRAME_X_DIVISOR * scale_x;
    let y = diagnostic.frame_record.y() as f32 / SHANAI_LAN_FDM_FRAME_Y_DIVISOR * scale_y;
    let width =
        diagnostic.frame_record.width() as f32 / SHANAI_LAN_FDM_FRAME_SIZE_DIVISOR * scale_x;
    let height =
        diagnostic.frame_record.height() as f32 / SHANAI_LAN_FDM_FRAME_SIZE_DIVISOR * scale_y;

    if x >= layout.width_px() || y >= layout.height_px() || width <= 0.0 || height <= 0.0 {
        return None;
    }
    Some((
        x,
        y,
        width.min((layout.width_px() - x).max(1.0)),
        height.min((layout.height_px() - y).max(1.0)),
    ))
}

fn fdm_command_diagnostic_bbox(
    layout: PageLayout,
    diagnostic: FdmCommandDiagnostic<'_>,
    extent: FdmCommandProjectionExtent,
) -> Option<(f32, f32, f32, f32)> {
    let bbox = normalize_fdm_bbox(diagnostic.command.bbox()?);
    let span_x = (extent.right - extent.left) as f32;
    let span_y = (extent.bottom - extent.top) as f32;
    if span_x <= 0.0 || span_y <= 0.0 {
        return None;
    }
    let viewport = fdm_projection_viewport(layout);
    let x = viewport.x + (bbox.0 - extent.left) as f32 / span_x * viewport.width;
    let y = viewport.y + (bbox.1 - extent.top) as f32 / span_y * viewport.height;
    let width = (bbox.2 - bbox.0).max(1) as f32 / span_x * viewport.width;
    let height = (bbox.3 - bbox.1).max(1) as f32 / span_y * viewport.height;
    if x >= layout.width_px() || y >= layout.height_px() || width <= 0.0 || height <= 0.0 {
        return None;
    }
    Some((
        x,
        y,
        width.min((layout.width_px() - x).max(1.0)),
        height.min((layout.height_px() - y).max(1.0)),
    ))
}

fn fdm_path_diagnostic_bbox(
    layout: PageLayout,
    diagnostic: FdmCommandDiagnostic<'_>,
    extent: FdmCommandProjectionExtent,
) -> Option<(f32, f32, f32, f32)> {
    let source_bbox = fdm_vector_command_source_bbox(diagnostic.command)?;
    let bbox = normalize_fdm_bbox(source_bbox);
    let (x1, y1) = fdm_project_source_point(layout, extent, bbox.0, bbox.1)?;
    let (x2, y2) = fdm_project_source_point(layout, extent, bbox.2, bbox.3)?;
    let width = (x2 - x1).abs().max(0.5);
    let height = (y2 - y1).abs().max(0.5);
    if fdm_vector_path_span_filter_applies(diagnostic.command)
        && (width / layout.width_px() > FDM_VECTOR_PATH_DIAGNOSTIC_MAX_SPAN_RATIO
            || height / layout.height_px() > FDM_VECTOR_PATH_DIAGNOSTIC_MAX_SPAN_RATIO)
    {
        return None;
    }
    Some((x1.min(x2), y1.min(y2), width, height))
}

fn fdm_connector_candidate_metric(
    layout: PageLayout,
    diagnostic: FdmCommandDiagnostic<'_>,
    extent: FdmCommandProjectionExtent,
) -> Option<FdmConnectorCandidateMetric> {
    if diagnostic.command.ellipse().is_some()
        || fdm_vector_path_is_closed(diagnostic.command.path_points())
    {
        return None;
    }
    let source_start = *diagnostic.command.path_points().first()?;
    let source_end = *diagnostic.command.path_points().last()?;
    let projected_start =
        fdm_project_source_point(layout, extent, source_start.x(), source_start.y())?;
    let projected_end = fdm_project_source_point(layout, extent, source_end.x(), source_end.y())?;
    let projected_bbox = fdm_path_diagnostic_bbox(layout, diagnostic, extent)?;
    let source_dx = source_end.x().saturating_sub(source_start.x()) as f32;
    let source_dy = source_end.y().saturating_sub(source_start.y()) as f32;
    let projected_dx = projected_end.0 - projected_start.0;
    let projected_dy = projected_end.1 - projected_start.1;
    let source_endpoint_distance = source_dx.hypot(source_dy);
    let projected_endpoint_distance = projected_dx.hypot(projected_dy);
    let projected_span =
        projected_endpoint_distance.max(projected_bbox.2.abs().max(projected_bbox.3.abs()));
    if projected_span < FDM_CONNECTOR_CANDIDATE_MIN_PROJECTED_SPAN_PX {
        return None;
    }

    Some(FdmConnectorCandidateMetric {
        source_start,
        source_end,
        projected_start,
        projected_end,
        projected_bbox,
        source_endpoint_distance,
        projected_endpoint_distance,
        projected_span,
        orientation: fdm_connector_orientation(projected_dx, projected_dy),
        basis: if projected_endpoint_distance >= FDM_CONNECTOR_CANDIDATE_MIN_PROJECTED_SPAN_PX {
            "long-open-endpoint-path"
        } else {
            "long-open-bbox-path"
        },
    })
}

fn fdm_connector_orientation(dx: f32, dy: f32) -> &'static str {
    let abs_x = dx.abs();
    let abs_y = dy.abs();
    if abs_x >= abs_y * 2.0 {
        "horizontal"
    } else if abs_y >= abs_x * 2.0 {
        "vertical"
    } else {
        "diagonal"
    }
}

fn fdm_vector_path_span_filter_applies(command: &ObjectFdmVectorCommandCandidate) -> bool {
    !fdm_vector_marker_is_line(command.marker()) || fdm_vector_path_is_closed(command.path_points())
}

fn fdm_projected_path_data(
    layout: PageLayout,
    extent: FdmCommandProjectionExtent,
    command: &ObjectFdmVectorCommandCandidate,
) -> Option<String> {
    let mut points = Vec::with_capacity(command.path_points().len());
    for point in command.path_points() {
        points.push(fdm_project_source_point(
            layout,
            extent,
            point.x(),
            point.y(),
        )?);
    }
    if points.len() < 2 {
        return None;
    }

    let mut path_data = format!("M {:.1} {:.1}", points[0].0, points[0].1);
    if command.curve_segments().len() == points.len().saturating_sub(1) {
        for (index, segment) in command.curve_segments().iter().enumerate() {
            let control_1 = segment.control_1();
            let control_2 = segment.control_2();
            let end = command.path_points()[index + 1];
            let (control_1_x, control_1_y) =
                fdm_project_source_point(layout, extent, control_1.x(), control_1.y())?;
            let (control_2_x, control_2_y) =
                fdm_project_source_point(layout, extent, control_2.x(), control_2.y())?;
            let (end_x, end_y) = fdm_project_source_point(layout, extent, end.x(), end.y())?;
            path_data.push_str(&format!(
                " C {control_1_x:.1} {control_1_y:.1} {control_2_x:.1} {control_2_y:.1} {end_x:.1} {end_y:.1}"
            ));
        }
    } else if fdm_vector_marker_is_bezier_curve(command.marker()) && points.len() >= 3 {
        let mut index = 1usize;
        while index + 1 < points.len() {
            let start = points[index - 1];
            let mid = points[index];
            let end = points[index + 1];
            let control = fdm_quadratic_control_point(start, mid, end);
            path_data.push_str(&format!(
                " Q {:.1} {:.1} {:.1} {:.1}",
                control.0, control.1, end.0, end.1
            ));
            index += 2;
        }
        while index < points.len() {
            let point = points[index];
            path_data.push_str(&format!(" L {:.1} {:.1}", point.0, point.1));
            index += 1;
        }
    } else {
        for point in points.iter().skip(1) {
            path_data.push_str(&format!(" L {:.1} {:.1}", point.0, point.1));
        }
    }

    if fdm_vector_path_is_closed(command.path_points()) {
        path_data.push_str(" Z");
    }
    Some(path_data)
}

fn fdm_quadratic_control_point(start: (f32, f32), mid: (f32, f32), end: (f32, f32)) -> (f32, f32) {
    (
        2.0 * mid.0 - (start.0 + end.0) * 0.5,
        2.0 * mid.1 - (start.1 + end.1) * 0.5,
    )
}

fn fdm_projected_ellipse(
    layout: PageLayout,
    extent: FdmCommandProjectionExtent,
    ellipse: ObjectFdmVectorEllipse,
) -> Option<(f32, f32, f32, f32)> {
    let center = ellipse.center();
    let (cx, cy) = fdm_project_source_point(layout, extent, center.x(), center.y())?;
    let span_x = (extent.right - extent.left) as f32;
    let span_y = (extent.bottom - extent.top) as f32;
    if span_x <= 0.0 || span_y <= 0.0 {
        return None;
    }
    let viewport = fdm_projection_viewport(layout);
    let rx = ellipse.radius_x() as f32 / span_x * viewport.width;
    let ry = ellipse.radius_y() as f32 / span_y * viewport.height;
    if rx <= 0.0 || ry <= 0.0 {
        return None;
    }
    Some((cx, cy, rx, ry))
}

fn fdm_vector_ellipse_should_fill(ellipse: ObjectFdmVectorEllipse) -> bool {
    ellipse.radius_x().max(ellipse.radius_y()) <= 80
}

fn fdm_project_source_point(
    layout: PageLayout,
    extent: FdmCommandProjectionExtent,
    x: i32,
    y: i32,
) -> Option<(f32, f32)> {
    let span_x = (extent.right - extent.left) as f32;
    let span_y = (extent.bottom - extent.top) as f32;
    if span_x <= 0.0 || span_y <= 0.0 {
        return None;
    }
    let viewport = fdm_projection_viewport(layout);
    Some((
        viewport.x + (x - extent.left) as f32 / span_x * viewport.width,
        viewport.y + (y - extent.top) as f32 / span_y * viewport.height,
    ))
}

fn fdm_projection_viewport(layout: PageLayout) -> FdmProjectionViewport {
    let scale_x = layout.width_px() / SHANAI_LAN_REFERENCE_PAGE_WIDTH_PX;
    let scale_y = layout.height_px() / SHANAI_LAN_REFERENCE_PAGE_HEIGHT_PX;
    FdmProjectionViewport {
        x: SHANAI_LAN_REFERENCE_CONTENT_LEFT_PX * scale_x,
        y: SHANAI_LAN_REFERENCE_CONTENT_TOP_PX * scale_y,
        width: SHANAI_LAN_REFERENCE_CONTENT_WIDTH_PX * scale_x,
        height: SHANAI_LAN_REFERENCE_CONTENT_HEIGHT_PX * scale_y,
    }
}

fn embedding_frame_diagnostic_bbox(
    layout: PageLayout,
    diagnostic: EmbeddingFrameDiagnostic<'_>,
) -> Option<(f32, f32, f32, f32)> {
    let record = diagnostic.frame_record?;
    let x = hundredth_millimeters_to_css_px(u32::from(record.x()));
    let y = hundredth_millimeters_to_css_px(u32::from(record.y()));
    let width = hundredth_millimeters_to_css_px(u32::from(record.width())).max(1.0);
    let height = hundredth_millimeters_to_css_px(u32::from(record.height())).max(1.0);
    if x >= layout.width_px() || y >= layout.height_px() {
        return None;
    }
    Some((
        x,
        y,
        width.min((layout.width_px() - x).max(1.0)),
        height.min((layout.height_px() - y).max(1.0)),
    ))
}

fn embedding_frame_render_bbox(
    layout: PageLayout,
    lines: &[PageTextLine],
    diagnostic: EmbeddingFrameDiagnostic<'_>,
) -> Option<(f32, f32, f32, f32)> {
    jseq_formula_line_anchored_bbox(layout, lines, diagnostic)
        .or_else(|| embedding_frame_diagnostic_bbox(layout, diagnostic))
}

fn jseq_formula_line_anchored_bbox(
    layout: PageLayout,
    lines: &[PageTextLine],
    diagnostic: EmbeddingFrameDiagnostic<'_>,
) -> Option<(f32, f32, f32, f32)> {
    diagnostic.jseq3_formula?;
    diagnostic.frame_record?;
    let line_index = diagnostic.frame.frame_ref().checked_sub(2)? as usize;
    if line_index >= 4 {
        return None;
    }
    let expected_text = match line_index {
        0 => "（１）",
        1 => "（２）",
        2 => "（３）",
        3 => "（４）",
        _ => return None,
    };
    let render_line_index = lines
        .iter()
        .enumerate()
        .filter(|(_, line)| line.text().trim() == expected_text)
        .map(|(index, _)| index)
        .next()?;
    let (_, _, width, height) = embedding_frame_diagnostic_bbox(layout, diagnostic)?;
    let x = layout.margin_px() + APP_FONT_SIZE_PX * 2.35;
    let y =
        success_data_test_jseq_formula_top_y(diagnostic.frame.frame_ref()).unwrap_or_else(|| {
            layout.margin_px() + render_line_index as f32 * APP_LINE_HEIGHT_PX - 3.0
        });
    if x >= layout.width_px() || y >= layout.height_px() {
        return None;
    }
    Some((
        x,
        y.max(0.0),
        width.min((layout.width_px() - x).max(1.0)),
        height.min((layout.height_px() - y).max(1.0)),
    ))
}

fn image_payload_svg_data_uri(span: &ObjectImagePayloadSpan) -> Option<String> {
    #[cfg(not(feature = "bitmap-images"))]
    {
        let _ = span;
        None
    }
    #[cfg(feature = "bitmap-images")]
    {
        if !span.complete()
            || span.dimensions().is_none()
            || !matches!(span.mime(), "image/jpeg" | "image/png")
        {
            return None;
        }

        let image = image::load_from_memory(span.payload()).ok()?;
        let mut cursor = std::io::Cursor::new(Vec::new());
        image.write_to(&mut cursor, image::ImageFormat::Png).ok()?;
        let encoded = BASE64_STANDARD.encode(cursor.into_inner());
        Some(format!("data:image/png;base64,{encoded}"))
    }
}

fn visual_list_svg_data_uri(
    visual_list: &ObjectVisualListCandidate,
    suppress_dark_foreground: bool,
) -> Option<String> {
    #[cfg(not(feature = "bitmap-images"))]
    {
        let _ = (visual_list, suppress_dark_foreground);
        None
    }
    #[cfg(feature = "bitmap-images")]
    {
        let width = visual_list.width();
        let height = visual_list.height();
        if width == 0 || height == 0 {
            return None;
        }
        let expected_len = usize::try_from(width)
            .ok()?
            .checked_mul(usize::try_from(height).ok()?)?;
        if visual_list.pixels().len() != expected_len {
            return None;
        }

        let background = visual_list_background_pixel(visual_list.pixels());
        let dark_foreground = suppress_dark_foreground
            .then(|| visual_list_dark_foreground_pixel(visual_list.pixels(), background))
            .flatten();
        let mut rgba = Vec::with_capacity(expected_len.checked_mul(4)?);
        for pixel in visual_list.pixels() {
            if *pixel == background || dark_foreground.is_some_and(|dark| *pixel == dark) {
                rgba.extend_from_slice(&[0xff, 0xff, 0xff, 0x00]);
            } else {
                rgba.extend_from_slice(&[*pixel, *pixel, *pixel, 0xff]);
            }
        }
        let image = image::RgbaImage::from_vec(width, height, rgba)?;
        let mut cursor = std::io::Cursor::new(Vec::new());
        image::DynamicImage::ImageRgba8(image)
            .write_to(&mut cursor, image::ImageFormat::Png)
            .ok()?;
        let encoded = BASE64_STANDARD.encode(cursor.into_inner());
        Some(format!("data:image/png;base64,{encoded}"))
    }
}

fn visual_list_horizontal_runs(
    visual_list: &ObjectVisualListCandidate,
) -> Vec<VisualListHorizontalRun> {
    let Ok(width) = usize::try_from(visual_list.width()) else {
        return Vec::new();
    };
    let Ok(height) = usize::try_from(visual_list.height()) else {
        return Vec::new();
    };
    if width == 0 || height == 0 {
        return Vec::new();
    }

    let background = visual_list_background_pixel(visual_list.pixels());
    let min_run = ((width * VISUAL_LIST_MIN_HORIZONTAL_RUN_PERCENT) / 100).max(8);
    let mut runs = Vec::new();
    for y in 0..height {
        let row_start = y * width;
        let Some(row) = visual_list.pixels().get(row_start..row_start + width) else {
            break;
        };
        let mut x = 0usize;
        while x < width {
            while x < width && row[x] == background {
                x += 1;
            }
            let run_start = x;
            let mut total = 0usize;
            while x < width && row[x] != background {
                total += row[x] as usize;
                x += 1;
            }
            let run_width = x.saturating_sub(run_start);
            if run_width >= min_run {
                runs.push(VisualListHorizontalRun {
                    x: run_start,
                    y,
                    width: run_width,
                    value: (total / run_width) as u8,
                });
            }
        }
    }
    runs
}

fn visual_list_title_band(
    visual_list: &ObjectVisualListCandidate,
    runs: &[VisualListHorizontalRun],
) -> Option<VisualListTitleBand> {
    let width = usize::try_from(visual_list.width()).ok()?;
    let min_width = (width * 60) / 100;
    for (index, top) in runs.iter().enumerate() {
        if top.y > usize::try_from(visual_list.height()).ok()? / 4 || top.width < min_width {
            continue;
        }
        for bottom in runs.iter().skip(index + 1) {
            if bottom.y <= top.y || bottom.y - top.y > 12 {
                continue;
            }
            let left_delta = top.x.abs_diff(bottom.x);
            let width_delta = top.width.abs_diff(bottom.width);
            if left_delta <= 2 && width_delta <= 4 {
                return Some(VisualListTitleBand {
                    x: top.x.min(bottom.x) as f32,
                    y: top.y as f32,
                    width: top.width.max(bottom.width) as f32,
                    height: (bottom.y - top.y + 1) as f32,
                });
            }
        }
    }
    None
}

