fn success_data_test_jseq_formula_top_y(frame_ref: u32) -> Option<f32> {
    let slot_index = match frame_ref {
        2 => 1,
        3 => 2,
        4 => 3,
        5 => 4,
        _ => return None,
    };
    let top_offset = match frame_ref {
        3 => 13.0,
        _ => 3.0,
    };
    SUCCESS_DATA_TEST_TOP_TEXT_SLOTS
        .get(slot_index)
        .map(|slot| (slot.y - top_offset).max(0.0))
}

fn success_data_test_formula_text_slots(
    document: &Document,
    diagnostic: EmbeddingFrameDiagnostic<'_>,
) -> Option<Vec<ResolvedJseqFormulaTextSlot>> {
    if !document_has_success_data_test_projection_evidence(document) {
        return None;
    }
    let formula = diagnostic.jseq3_formula?;
    if formula.text_tokens().is_empty() {
        return None;
    }
    let slots = SUCCESS_DATA_TEST_FORMULA_TEXT_SLOTS
        .iter()
        .copied()
        .filter(|slot| slot.embedding_index == diagnostic.frame.embedding_index())
        .filter_map(|slot| resolve_jseq_formula_text_slot(formula, slot))
        .collect::<Vec<_>>();
    (!slots.is_empty()).then_some(slots)
}

fn resolve_jseq_formula_text_slot(
    formula: &ObjectJseq3FormulaCandidate,
    slot: SuccessDataTestFormulaTextSlot,
) -> Option<ResolvedJseqFormulaTextSlot> {
    let text = if let Some(text) = formula
        .text_runs()
        .iter()
        .map(ObjectJseq3TextRunCandidate::text)
        .find_map(|text| {
            if slot.text == text {
                return Some(text.to_string());
            }
            let suffix = slot.text.strip_prefix(text)?;
            suffix
                .chars()
                .all(jseq_formula_compat_delimiter)
                .then(|| format!("{text}{}", normalize_jseq_formula_delimiters(suffix)))
        }) {
        text
    } else if slot.text.chars().all(jseq_formula_compat_delimiter) {
        normalize_jseq_formula_delimiters(slot.text)
    } else {
        return None;
    };
    Some(ResolvedJseqFormulaTextSlot {
        text,
        x: slot.x,
        baseline_y: slot.baseline_y,
        font_size: slot.font_size,
    })
}

fn jseq_formula_compat_delimiter(character: char) -> bool {
    matches!(character, '（' | '）' | '(' | ')')
}

fn normalize_jseq_formula_delimiters(text: &str) -> String {
    text.chars()
        .map(|character| match character {
            '（' => '(',
            '）' => ')',
            other => other,
        })
        .collect()
}

fn success_data_test_top_text_line_should_skip(
    document: &Document,
    page_number: usize,
    line: &PageTextLine,
) -> bool {
    if success_data_test_answer_sheet_page(document, page_number) {
        return true;
    }
    if success_data_test_top_text_projection(document, page_number).is_none() {
        return false;
    }
    let text = line.text().trim();
    matches!(
        text,
        "１，次の計算をしなさい"
            | "（１）"
            | "（２）"
            | "（３）"
            | "（４）"
            | "たものである。"
            | "３、右の図のような円錐について次の問に答えなさい。"
            | "（１）この円錐の体積を求めなさい。"
            | "（２）表面積を求めなさい。"
            | "（３）この円錐の展開図の側面のおうぎ形の"
            | "中心角を求めなさい。"
            | "４、次の図で∠ｘの大きさを求めなさい。"
            | "５、右の図は、半径ｒの球とその球がちょうど入る円柱、"
            | "その円柱にちょうど入る円錐を表している。"
            | "（１）球の体積をｒを使って表しなさい。"
            | "（２）これらの、球、円柱、円錐の体積の間には"
            | "どのような関係がありますか。"
    ) || text.starts_with("２，下の表は、ｃが斜辺の直角三角形")
        || text.contains("空欄を埋めて表を完成させなさい")
        || (text.contains("（１）") && text.contains("（２）") && text.contains("（３）"))
}

fn success_data_test_answer_sheet_page(document: &Document, page_number: usize) -> bool {
    page_number == 2
        && success_data_test_answer_sheet_tail_evidence(document)
        && success_data_test_answer_sheet_fdm_text_candidate(document).is_some()
        && embedding_frame_diagnostics(document)
            .into_iter()
            .any(|diagnostic| {
                success_data_test_title_art_diagnostic_for_page(document, diagnostic, page_number)
            })
}

fn success_data_test_answer_sheet_tail_evidence(document: &Document) -> bool {
    let plain_text = document_plain_text(document);
    plain_text.contains("(1)表面積の比")
        && plain_text.contains("ＡＢ")
        && plain_text.contains("ＡＣ")
        && plain_text.contains("ｃｍ")
}

